INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2149495','Вибір є','Музика: Юрій Воронюк Слова: Юрій Воронюк. Виконує: Юрій Воронюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ми колись у світ приходим
Й маємо колись піти,
А між тим - життя пригоди,
Шлях нелегкий до мети.
Ми повинні відповісти
На запитання буття,
І вписати в аркуш чистий
Вірші нашого життя.

Приспів:
Вибір є у кожній долі:
Хочеш радощів - плати!
Хочеш бути вітром в полі -
Про чужі не мрій світи!
Хочеш жити пустоцвітом
Про усе забудь, цвіти!
Покохаєш - вмій любити!
Станеш зіркою - світи!

Світ навколо мальовничий,
Безліч звабливих прикрас,
Небо в кожного обличчі
Відзеркалюється в нас.
Ми живем чи існуєм,
А роки, як сон летять,
Маєм те, що намалюєм
На полотнищі життя.

Приспів. (2)','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2149495'), datetime('now')),datetime('now'));
