INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2150012','У містечку Віфлеємі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'У містечку Віфлеємі,
У містечку Віфлеємі
Божа Мати сина мала,
В пелени го повивала.

І зійшлися всі святії,
Взяли книги золотії,
Взяли книги всі читати,
Яке би йому ім''я дати.

Дали йому святий Павло,
Божа Мати не злюбила,
Од престолу й одступила,
Вся ся земля засмутила.

І зійшлися всі святії,
Взяли книги золотії,
Взяли книги всі читати,
Яке би йому ім''я дати.

Дали йому святий Петро,
Божа Мати не злюбила,
Од престолу й одступила,
Вся ся земля засмутила.

Знов зійшлися всі святії,
Взяли книги золотії,
Взяли книги ті читати,
Яке би йому ім''я дати.

Дали йому Ісус Христос,
Божа Мати ізлюбила,
До престолу приступила,
Вся ся земля звеселила.

Ой, радуйтесь, християни,
Ой, радуйтесь, християни,
Бо Христос є межи вами,
Бо Христос є межи вами!
Бо Христос є межи вами!','[''pisni.org.ua'', ''cat:christian'', ''cat:kolyadky'', ''Пісні на християнську тематику'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2150012'), datetime('now')),datetime('now'));
