INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2149395','Коляда-колядка','Музика: Павло Табаков Слова: Павло Табаков. Виконує: Павло Табаков','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'У святкову Ніч Різдвяну
