INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2150055','Свят Бог народився','(Що за радість). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Що за радість для нас всіх настала,
Яка досі в світі не бувала.
Свят Бог народився,
Людям об''явився на земли!

Ангел вістю пастирям голосить,
До Ісуса на поклін їх просить.
Свят Бог народився,
Людям об''явився на земли!

Вже й три царі прийшли аж зі Сходу
І витають творця всього роду.
Свят Бог народився,
Людям об''явився на земли!

Ірод того не може збагнути,
Всіх питає: Чи се може бути?
Свят Бог народився,
Людям об''явився на земли!

Казав діти дворічні стинати,
Щоб враз з ними Христу життя взяти.
Свят Бог народився,
Людям об''явився на земли!

Не пошкодить Христу злобне діло,
До Єгипту він ся скриє ціло.
Свят Бог народився,
Людям об''явився на земли!

Прийде скоро Іроду заглада,
А нам в Бозі втіха і відрада.
Свят Бог народився,
Людям об''явився на земли!

Дай нм, Спасе, вік усім прожити,
Щирим серцем все тебе хвалити.
Свят Бог народився,
Людям об''явився на земли!

Свят Бог народився,
Людям об''явився на земли!','[''pisni.org.ua'', ''cat:kolyadky'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2150055'), datetime('now')),datetime('now'));
