INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2149563','В суботу пізненько, в неділю раненько','Українська народна пісня. Виконує: Кубанський Козачий Хор','uk','ukraine_before_1917',NULL,NULL,NULL,'Така пісня вже є на сайті, але цей варіант має чудову фонограму, яку надсилаю за адресою.','В суботу пізненько,
В неділю раненько
Кувала зозуля
В саду жалібненько.

Ой то ж не зозуля,
То рідная мати.
Вона провожає
Синочка в солдати.

Іди, іди, синку,
Іди, не барися,
Через два годочки
Додому вернися.

Ой рад би я, мамо,
Додому вернуться
Та тії ворони
В воротях спіткнуться.

Не плач, моя мамо,
В тугу не давайся,
За граті ворони,
Назад повертайся.

В суботу пізненько,
В неділю раненько
Кувала зозуля
В саду жалібненько','[''pisni.org.ua'', ''cat:rekrutski'', ''Рекрутські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2149563'), datetime('now')),datetime('now'));
