INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2148124','Тобою радується','Виконує: Надія Церкви','uk','ukraine_1991',NULL,NULL,NULL,'Чоловічий хор "Надія Церкви". Літургічний рік. Тобою радується (А. Гнатишин)','Тобою радується, Благодатная, всяка твар,
