INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2149777','В місті Вефлеємі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'В місті Вефлеємі нині новина,
Бо Пречиста Діва сина родила.
Сина породила, в ясла оповила,        |
Божого Сина.                          | (2)

А Йосип старенький біля них стоїть,
Для дитя Ісуса пелени стелить.
Дитя повиває, пісню му співає,        |
Божому Сину.                          | (2)

Прийшли тріє царі з подарунками,
А над ними зорі ополонками.
Прийшли тріє царі, принесли му дари,  |
Божому Сину.                          | (2)

Ангели на небі славу співають
І людям на землі проповідують:
Слава Рожденному! Щастя в кожнім дому |
І всім на землі!                      | (2)

В місті Вефлеємі нині новина,
Бо Пречиста Діва сина родила.
Сина породила, в ясла оповила,        |
Божого Сина.                          | (2)','[''pisni.org.ua'', ''cat:kolyadky'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2149777'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2149777','В місті Вефлеємі','В місті Вефлеємі нині новина,
Бо Пречиста Діва сина родила.
Сина породила, в ясла оповила,        |
Божого Сина.                          | (2)

А Йосип старенький біля них стоїть,
Для дитя Ісуса пелени стелить.
Дитя повиває, пісню му співає,        |
Божому Сину.                          | (2)

Прийшли тріє царі з подарунками,
А над ними зорі ополонками.
Прийшли тріє царі, принесли му дари,  |
Божому Сину.                          | (2)

Ангели на небі славу співають
І людям на землі проповідують:
Слава Рожденному! Щастя в кожнім дому |
І всім на землі!                      | (2)

В місті Вефлеємі нині новина,
Бо Пречиста Діва сина родила.
Сина породила, в ясла оповила,        |
Божого Сина.                          | (2)');
