INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_214993','Щедрик','Музика: Іван Сльота Слова: Олександр Богачук. Виконує: Ансамбль Льонок, Тріо "Лелія"','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Щедрик, щедрик, щедрівочко,
Йди з хати до хати
Добрих друзів добрим словом —
Серцем привітати!
Стали в парі, стали в парі
Стрілочки-сестриці.
Вище чари, повні чари,
Чари-чарівниці!

Приспів:
Пироги, вилазьте з печі,
Наливайтесь, вина!
Добрий вечір, щедрий вечір,
Мати Україно!

Килим, килим, килимочку,
Клич гостей в оселі,
І співанкою гучною
Розстелись по стелі!
Вітер басом, вітер басом,
А скрипками — хуга!
Бубон місяця нагрівся
Від пруга до пруга!

Приспів.

Сніговиця білолиця
І мороз червоний —
Руки в боки й вихилясом —
Аж регочуть гони!
Хто там, хто там в шибку стука?
Може, гість далекий?
Може, змерзли біля вікон
Молоді смереки!

Приспів.

То щедрівка-мандрівочка
Йде з хати до хати...
Добрий вечір, щедрий вечір,
Україно-мати!','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_214993'), datetime('now')),datetime('now'));
