INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2147952','Пречистая Діва по світу ходила','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'1. Пречистая Діва по світу ходила,
Прийшла до багача, прийшла до багача, на ніч ся просила:

2. - Пане господар''ю, переночуй мене,
Бо темная нічка, бо темная нічка надходить на мене.

3. А той пан господар не хтів ночувати,
Тільки сказав слугам, тільки сказав слугам собаками гнати.

4. Пречистая Діва по світу ходила,
Прийшла до бідного, прийшла до бідного, на ніч ся просила:

5. - Пане господар''ю, переночуй мене,
Бо темная нічка, бо темная нічка надходить на мене.

6. - Можу тя, можу тя переночувати,
Тільки я не маю, тільки я не маю вечероньки дати.

7. - Не треба, не треба вечероньки тої,
Тільки пусти мине, тільки пусти мене до стаєньки свої.

8. - Вставай, господини, бо вже''с ся виспала,
Бо наша стаєнка, ба наша стаєнка світлом засіяла.

9. Чи то місяць сходить, чи сонце заходить,
То Пречиста Діва, то Пречиста Діва свого Сина родить.

10.- Якби''м була знала, що то Матір Божа,
Була б відпустила, була б відпустила своє бідне ложе.

11.- Якби''м була знала, що Матір з Ісусом,
Була б постелила, була б постелила біленьким обрусом.

12.- Якби''м була знала, що то Матір з Богом,
Була би''м лягала, була би''м лягала з дітьми під порогом.

13.- Не бійсь, гоподар''ю, не будеш мав трату,
Будеш мав від Бога, будеш мав від Бога велику заплату.    12_20081024vovczak_seans2_Пречистая Діва по світу ходила.mp3','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:narodni'', ''Колядки'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2147952'), datetime('now')),datetime('now'));
