INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2149920','Зійшла зірка чудна','Українська народна пісня. Виконує: Андрій Заліско','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Зійшла зірка чудна
З восток на полудне,
Над вертепом сіяє,     |
Трьом царям тут являє. | (2)

Зійшли з неба три царі,
Несуть Христу дари,
Ірод їх ся питає:      |
Куди йдете, три царі?  | (2)

І три царі зі Сходу
Відповіли Іроду:
Звізда ясна явила -    |
Діва Сина зродила.     | (2)

Зійшла зірка чудна
З восток на полудне,
Над вертепом сіяє,     |
Трьом царям тут являє. | (2)','[''pisni.org.ua'', ''cat:kolyadky'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2149920'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2149920','Зійшла зірка чудна','Зійшла зірка чудна
