INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2149919','Сумний був той Святий Вечір','Українська народна пісня. Виконує: невідомий виконавець, Сергій Лазановський, Анастасія Марків','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Сумний був той Святий Вечір
В сорок сьомім році,
По всій нашій Україні      |
Плач на кожнім кроці.      | (2)

Як на небі зірка
Почала сіяти,
Почав нарід до Святої      |
Вечері сідати.             | (2)

Сіли до вечері,
А діти питають:
Мамо, мамо, де наш Батько? |
Чом не вечеряють?          | (2)

А наш Батько, діти,
В далекім Сибірі,
Споминає Святий Вечір      |
По всій славній Україні.   | (2)

А там стара мати
За синами плаче,
Мала-м штири, як соколи,   |
А тепер я їх не бачу.      | (2)

Поможи нам, Боже,
Все це перебути,
Нашу неньку Україну        |
З кайданів розкути.        | (2)

О, Ісусе милий,
Змилуйся нам нині,
Даруй волю, даруй долю     |
Нашій славній Україні!     | (2)','[''pisni.org.ua'', ''cat:christian'', ''cat:istorychni'', ''cat:kolyadky'', ''cat:narodni'', ''cat:patriotic'', ''Пісні на християнську тематику'', ''Історичні пісні'', ''Колядки'', ''Народні пісні'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2149919'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2149919','Сумний був той Святий Вечір','Сумний був той Святий Вечір
В сорок сьомім році,
По всій нашій Україні      |
Плач на кожнім кроці.      | (2)

Як на небі зірка
Почала сіяти,
Почав нарід до Святої      |
Вечері сідати.             | (2)

Сіли до вечері,
А діти питають:
Мамо, мамо, де наш Батько? |
Чом не вечеряють?          | (2)

А наш Батько, діти,
В далекім Сибірі,
Споминає Святий Вечір      |
По всій славній Україні.   | (2)

А там стара мати
За синами плаче,
Мала-м штири, як соколи,   |
А тепер я їх не бачу.      | (2)

Поможи нам, Боже,
Все це перебути,
Нашу неньку Україну        |
З кайданів розкути.        | (2)

О, Ісусе милий,
Змилуйся нам нині,
Даруй волю, даруй долю     |
Нашій славній Україні!     | (2)');
