INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2150073','Христос родився!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'В Вифлеємі радість стала,
Зірка в небі засіяла,
В Вифлеємі Син родився,
Він у Бога воплотився
Від Пречистої Марії.

Приспів:
О, свята Марія Мати,    |
Ми прийшли Тебе витати, |
Христос родився!        | (2)

Він родився ще й не знає,
Що весь світ Його чекає.
В ньому Бога всі вбачають
І з мольбами припадають
До заступника-Ісуса.

Приспів.

Я молюся в цю хвилину,
Бережи мою родину,
Дай нам хліба, дай нам волю,
Для Вкраїни кращу долю,
О, молю тебе, Ісусе.

Приспів.','[''pisni.org.ua'', ''cat:christian'', ''cat:kolyadky'', ''cat:narodni'', ''Пісні на християнську тематику'', ''Колядки'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2150073'), datetime('now')),datetime('now'));
