INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_215226','Гей там з-за гори, з-за крем''яної',NULL,'uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'89',NULL,'Гей там з-за гори, з-за крем''яної
Фана малинова в''ється.
Гей, при долині в чеснім двобою
Військо стрілецькеє б''ється.

Гей, попереду курінний,
Гей, як той орел степовий.
Твердий, мов той кремінь,
Козаків своїх не зрадить,
Кроком він рушає
Раз, два, три.

Приспів:
Прощайте гори, гори,
І долина, долина
У бій іде дивізія "Галичина".

Годі нам, браття, в неволі томиться
І за Москву свою кров проливать,
Час вже настав Богу помолиться
І Україну - неньку визволять.

Від Сяну до Дону
Рушаймо додому,
У батьківський край
На зелені лани
Слава! Слава! Слава!
Слава не поляже,
Поки на Вкраїні
Є вірні сини.

Чуєш, козаче, чуєш, юначе,
Кличе вже сурма до бою.
За Україну, за неньку єдину
Гей же, до бою, до бою!','[''pisni.org.ua'', ''cat:strilecki'', ''Стрілецькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_215226'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_215226','Гей там з-за гори, з-за крем''яної','Гей там з-за гори, з-за крем''яної
