INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_21512','Де ти їдеш, Романочку, Романочку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'А вже весна скресла. Збірник гаївок. Львів, 2003.',NULL,'"Де ти їдеш, Романочку, Романочку?"
