INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2150318','Ой, пошила чоботи з бугая','Українська народна пісня. Виконує: Чоботи з Бугая','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, пошила чоботи з бугая,
Не бояться холоду, нічого...
Приспів:
Чоботи, чоботи з бугая,
Не бояться холоду, нічого...
Чоботи, чоботи ви мої,
Наробили клопоту ви мені...
Повісила чоботи на гвозді,
Сама себе ляснула по нозі...
Приспів.
На городі кури гребуться,
А в саду дівчата гуляють...
Приспів.
Щоб тії кури подохли,
А у кума щось відсохло...
Приспів.
Приїжджала сваха до свахи,
Притуляла руку до руки...
Приспів.
Ой, чим ближче рука до руки,
Тим щільніше сваха до свахи...
Приспів.
Ой, пошила чоботи з бугая,
Не бояться холоду, нічого...
Приспів. (3)','[''pisni.org.ua'', ''cat:zhartivlyvi'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2150318'), datetime('now')),datetime('now'));
