INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_215292','Ми зустрілися з тобою у Яремчі','Українська народна пісня. Виконує: Зорепад','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ми зустрілися з тобою у Яремчі,
Але смуток залишився в моїм серці.
Приспів:
Якби-м була знала, була б не кохала, |
І з тобою до півночі не стояла.      | (2)
Пішла мила по водицю до криниці,
А в милого очі сині, як зірниці.
Приспів.
Як настала та година розставання,
Обнімались, цілувались аж до рання.
Приспів.
Ой, порадьте, люди добрі, що робити?
Чи кохати, чи любити, чи лишити?
Приспів','[''pisni.org.ua'', ''cat:zhartivlyvi'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_215292'), datetime('now')),datetime('now'));
