INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2152777','Літр портвейну','Музика: Тостер Слова: Тостер. Виконує: Тостер','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Цілий день туди-сюди,
