INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2153461','Ой, червоно сонце сходит','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, червоно сонце сходит,
Червоно заходит,
Хтів би я ся довідати,     |
Що дівчина робит.          | (2)

Хтів би я ся довідати,
Хтів би ся дізнати:
Чи дозволит гарна любка    |
Старости післати?          | (2)

Ой, позволю, козаченьку,
Позволю, позволю,
Тільки прошу, козаченьку,  |
Вороняче зілля.            | (2)

Ой, сів я си на коника,
Їду дорогами,
Ой, здибав я те тройзілля  |
Межи долинами.             | (2)

Ой, здибав я те тройзілля,
Став його копати,
Надлетіла зозуленьку,      |
Зачала кувати.             | (2)

Нащо ж тобі, козаченьку,
Ой, того тройзілля,
Коли ж твоя дівчиноньку    |
Справляє весілля?          | (2)

Ой, приїхав я до хати,
Став у сінях ззаді,
А вже моя дівчинонька      |
Сидить на посаді.          | (2)

Зайшов тихо поміж гості,
Сідаю під стінку,
А до мене добрі люди       |
П''ють вино-горівку.        | (2)

Ой, не хочу, люди добрі,
Вашої горівки,
Тільки хочу промовити      |
Півслова до дівки.         | (2)

Правов ручков, правов ручков
Дівчину вітає,
Лівов ручков, лівов ручков |
Шабельку виймає.           | (2)

А як гостра шабелина
Угорі збреніла -
То вже тії дівчиноньці     |
Голова злетіла.            | (2)','[''pisni.org.ua'', ''cat:vesilni'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2153461'), datetime('now')),datetime('now'));
