INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2152920','Не жди докорів','Музика: Олександр Білаш Слова: Олександр Олесь','uk','ukraine_1991',NULL,NULL,'Олександр Білаш. Романси для середнього голосу з фортепіано. К.: Мистецво. - 1966. - 50 с.',NULL,'Не жди докорів і погріз,
Ні зайвих слів, ні зайвих сліз,
Бо я їх всі в собі спалю,
Бо я люблю тебе, люблю.

Літа пливуть і в мряці літ
Дочасно гасне серця цвіт.
Цвісти б, горіть, я цвіт гублю,
Бо я тебе люблю, люблю.

Ні, сліз докірливих не жди...
Постій, не плач, постій, не жди.
Замовкну я, уста стулю, -
Люблю, люблю, люблю, люблю.','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2152920'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2152920','Не жди докорів','Не жди докорів і погріз,
