INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2152919','Цвітуть бузки','Музика: Олександр Білаш, Сергій Ярунський Слова: Максим Рильський','uk','ukraine_1991',NULL,NULL,'Олександр Білаш. Романси для середнього голосу з фортепіано. К.: Мистецво. - 1966. - 50 с.',NULL,'Цвітуть бузки, садок біліє
І тихо ронить пелюстки,
Напівзабуте знову мріє, |
Як помах милої руки.    | (2)

У небі вітер кучерявий
Колише теплую блакить,
І на землі гойдає трави,
І затихає, й знов шумить.

І раптом схоплює на крила
Хвилясті співи журавлів, -
І давня казка, вічно мила,
Зринає крізь хвилястий спів.

Цвітуть бузки...','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2152919'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2152919','Цвітуть бузки','Цвітуть бузки, садок біліє
І тихо ронить пелюстки,
Напівзабуте знову мріє, |
Як помах милої руки.    | (2)

У небі вітер кучерявий
Колише теплую блакить,
І на землі гойдає трави,
І затихає, й знов шумить.

І раптом схоплює на крила
Хвилясті співи журавлів, -
І давня казка, вічно мила,
Зринає крізь хвилястий спів.

Цвітуть бузки...');
