INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2152495','Різдвяна хуртовина','Музика: Ірина Федишин Слова: Ірина Федишин. Виконує: Ірина Федишин','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'За вікном хуртовина, а у хаті тепло,
За столом вся родина, бо на дворі Різдво,
На душі тепло всім, нас єднає любов,
На столі три свічі, що дарують тепло.

Приспів:
Хай любов свята нашого Христа
Об''єднає разом нас, усі серця,
У святкову ніч присвіти від свіч,
Запаху куті і дідуха в різдвяну ніч.
Загадай бажання ти у співанні коляди,
Загадай!
Руки до Христа склади, помолися і скажи:
Не лишай!

За вікном хуртовина, а у хаті тепло,
Світу гарна новина - Бог на землю прийшов,
Щирий сміх, білий сніг ні на мить не зникають.
Ніч Різдва, ніч свята, небеса відкривають,
Небеса...

Приспів.

Не лишай! Не лишай! Не лишай!

Хай святе Різдво принесе добро,
В кожний дім тепло!
З колядою ти в кожен дім іди
І неси добро!

Приспів.','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:shchedrivky'', ''cat:suchasni-pisni-rizdvo'', ''Колядки'', ''Щедрівки'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2152495'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2152495','Різдвяна хуртовина','За вікном хуртовина, а у хаті тепло,
