INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2153952','Грай, музика','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'записано в с. Біла (Тернопільська область), упорядники: Петро Медведик, Олег Смоляк',NULL,'Грай, музика,
Будеш в небі
Й цимбалісти
Коло тебе.

Щоб цимбали
Добре грали,
А дівчата
Танцювали!

Грай, музика,
Дам ти бика,
Причепи си
До язика.

Трошки січки,
Трошки трини,
Трошки з вами,
Трошки з ними!','[''pisni.org.ua'', ''cat:kolomyyky'', ''cat:vesilni'', ''Коломийки'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2153952'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2153952','Грай, музика','Грай, музика,
