INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2153354','Ой чому ти не танцюєш, Галю, Галю, Галю, Галю?','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'1. - Ой чому ти не танцюєш, Галю, Галю, Галю, Галю?
