INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2153767','Сік землі','Музика: Владислав Толмачов Слова: Володимир Вихрущ. Виконує: Ніна Матвієнко, Раїса Кириченко','uk','ukraine_1991',NULL,NULL,'аудіозапис http://www.youtube.com/watch?v=eAT5sgqA6oc','http://www.youtube.com/watch?v=eAT5sgqA6oc','П''є моє коріння сік землі,
День лежить на білому крилі,
Подих вітру схилює жита,
Пролітають стомлені літа...

З роду в рід кладе життя мости,
Без коріння саду не цвісти,
Без стремління човен не пливе,
Без коріння сохне все живе.

З нами линуть у добрі і у журбі
Материнські очі голубі.
Чарівлива пісня живить нас
І сумління сповідає час.

З роду в рід кладе життя мости,
Без коріння саду не цвісти,
Без стремління човен не пливе,
Без коріння сохне все живе.

Є в моїх садах мале село,
Є криниця, чисте джерело,
А коли вертаюсь я з доріг,
Я цілую батьківський поріг.

З роду в рід кладе життя мости,
Без коріння саду не цвісти,
Без стремління човен не пливе,
Без коріння сохне все живе.','[''pisni.org.ua'', ''cat:patriotic'', ''cat:zahalni-cinnosti'', ''Патріотичні пісні'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2153767'), datetime('now')),datetime('now'));
