INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2153591','Наш староста','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'записано в с. Біла (Тернопільська область), упорядники: Петро Медведик, Олег Смоляк',NULL,'Наш староста впали з моста,
Аж ноги задерли.
