INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2154199','Голгота, хрест',NULL,'uk','ukraine_1991',NULL,NULL,NULL,NULL,'1. Голгота, хрест, важкі кроваві сни,
Товпа реве: "Розпни, розпни, розпни!"
І розп''яли - на голові вінок,
По каплі кров спливає з колючок.

2. Товпа реве: "Якщо ти Божий Син,
Зійди з хреста і сам себе спаси;
Якщо ж не Бог, а лиш юдейський цар,
То військами на ворогів удар."

3. А Ти мовчиш, здригаєшся, мов трус,
А Ти не Бог, лиш Назорей Ісус.
Товпа реве: "Розпни, розпни, розпни!"
Прости їм, Боже, бо сліпі вони','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:christ'', ''cat:strasni'', ''Церковні пісні'', ''Пісні до Ісуса Христа'', ''Страсні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2154199'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2154199','Голгота, хрест','1. Голгота, хрест, важкі кроваві сни,
Товпа реве: "Розпни, розпни, розпни!"
І розп''яли - на голові вінок,
По каплі кров спливає з колючок.

2. Товпа реве: "Якщо ти Божий Син,
Зійди з хреста і сам себе спаси;
Якщо ж не Бог, а лиш юдейський цар,
То військами на ворогів удар."

3. А Ти мовчиш, здригаєшся, мов трус,
А Ти не Бог, лиш Назорей Ісус.
Товпа реве: "Розпни, розпни, розпни!"
Прости їм, Боже, бо сліпі вони');
