INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_215318','Україно','(Там де вчора лежали руїни...). Слова: Біла гарячка. Виконує: Біла гарячка','uk','ukraine_1991',NULL,NULL,'1. Акорди: пісенник ОУМ "Спадщина"',NULL,'Там де вчора лежали руїни
