INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_215354','Де Дніпро наш котить хвилі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українські релігійні роздуми про Спасіння © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2003','Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. Господа Милосердного прохали та благали. І мов сонця птичка в полі воскресіння жде і волі. Заплакала Україна така її Доля. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції. Висловлювання: Ціна народности. Обіцянка цяцянка, а дурневі радість. — Народна мудрість Внутрішнє "Я": Для нас, для розуміння нашого сьогоднішнього внутрішнього "я", важна не тільки наша недавня козацька історія і не тільки князівські часи, але й також і всі попередні часи. — Вадим Щербаківський','Де Дніпро наш котить хвилі рве стрімкі пороги
Там Вкраїна вся зелена славний край розлогий     | (2)

Там Козацтво виростало слави волі добувало
Україно Україно славний край козачий             | (2)

І не стало Запоріжжя вже нема Гетьманів
Над степами України чути брязк кайданів          | (2)

І мов сонця птичка в полі воскресіння жде і волі
Україна Україна славний край розлогий            | (2)','[''pisni.org.ua'', ''cat:istorychni'', ''cat:kozacki'', ''cat:philosophic'', ''cat:suspilno-politychni'', ''Історичні пісні'', ''Козацькі пісні'', ''Філософські пісні'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_215354'), datetime('now')),datetime('now'));
