INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_215379','Києве мій','(Як тебе не любити, Києве мій!). Музика: Ігор Шамо Слова: Дмитро Луценко. Виконує: Містерія, Юрій Гуляєв, Тетяна Овсієнко, Дмитро Гнатюк','uk','ukraine_1991',NULL,NULL,'1. Аудіо-альбом "Пісні Ігоря Шамо". 2. Аудіо-альбом групи "Містерія"','Акорди подано спрощено. Ориґінальна тональність: 1) за джерелом [1] - "Fm"; 2) за джерелом [2] - "Ebm". Підібрано на слух за аудіо-джерелами [1] і [2]. * Тут за джерелом [1] у 1-му куплеті за другим разом замість поданого тут тексту співається: Вечорів оксамити, Мов щастя прибій... Як тебе не любити, Києве мій! ** Ймовірно, тут: "канни" - множина від слова "канна". Канна - трав''яниста рослина (або її квітка) родини каннових. *** Тут за джерелом [1] повторюється лише мелодія без тексту. **** При останньому повторі тут замітсь акорда "Em" звучить "Em6". Деякі акорди: Am/F# [2 0 2 2 1 0] Em* [3 2 2 0 0 0] або [x 2 2 0 0 3] C6 [x 3 x 2 1 3] Em6 [0 2 2 0 2 0] Підбір акордів: bohdanko@epost.com.ua','Вступ:  G C Dm E7 Am
Em H7 (x3)
Грає море зелене,
Тихий день догора.
Дорогими для мене
Стали схили Дніпра,
Де колишуться віти       |
Зако- ханих мрій...      | (x2)*
Як тебе не люби- ти,     |
Em* H7   Em             |
Ки-  єве мій!            |
В очі дивляться канни, **
Серце в них переллю.
Хай розкажуть коханій,
Як я вірно люблю.
Буду мріяти й жити   |
На крилах надій...   | (x2)***
Як тебе не любити,   |
