INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_215394','Білі каштани','Музика: Платон Майборода Слова: Андрій Малишко','uk','ukr_ssr_1919_1991',NULL,'1940','Українські народні романси. - К.: В-во АН УРСР, 1961. - С. 376.','Anrzej (член клубу): "Пісня написана орієнтовно в кінці 1940-х." Текст звірений за вказаним джерелом.','Білі каштани, світлі вогні,
Де б не бував я - любі мені.
Київські ночі, зустрічі в саду -
В серці, куди не піду.

Гори високі, синь Дніпрова,
Молодість наша вічно жива.
Київські ночі, зустрічі в саду -
В серці, куди не піду.

Ми покохались там, де дуби,
В київськім небі два голуби.
Кружать, здіймають крилонька свої,
Наче ми в парі, в сім''ї.

Так воно стане, так воно є,
Білі каштани - щастя моє.
Київські ночі, зустрічі в саду -
В серці, куди не піду.    Фонограма-мінус (midi)','[''pisni.org.ua'', ''cat:kyyiv'', ''Пісні про Київ'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_215394'), datetime('now')),datetime('now'));
