INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2153890','Було літо, було літо','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,'Трохи інший від сайтового варіянт.','Було літо було літо,
Та й стала зима,
Як не було пригодоньки гей, гей      |
Та й досі нема.                      | (2)

Стала  ж йому пригодонька
з Дону ідучи
В чистім полі при дорозі, гей, гей   |
Воли пасучи.                         | (2)

Занедужав чумаченько,
Заслаб та й лежить,
Ніхто ж в нього не спитає, гей, гей  |
Що в нього болить.                   | (2)

Скинув чумак сіру свиту,
Скинув ще й жупан
Воли ж мої круторогі, гей, гей       |
Хто ж вам буде пан?                  | (2)

Заревіли воли сиві
Тіло везучи,
Заплакали чумаченьки, гей, гей       |
За ним ідучи.                        | (2)

У неділю пораненьку
Ударили в дзвін.
То ж по тому чумакові, гей, гей      |
Що ходив на Дін                      | (2)    Аудіо (демо, 32 kbps)','[''pisni.org.ua'', ''cat:chumacki'', ''Чумацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2153890'), datetime('now')),datetime('now'));
