INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2154293','Коломийка "Миколаю"','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Kulik A., Pleśniak P. Dla Oli na słowiańską nutę. Wybrane pieśni łemkowskie, bojkowskie, słowackie, polskie i inne. - Mińsk Mazowiecki, 2001. – 16 p.',NULL,'Миколаю, я умираю,
Бігай по горілку,
Ой, не бери одну фляшку,
Лем цілу барилку.

Ой, умираю, моя мамцю,
Умираю, умираю,
На смертной постілонці
На хлопці моргаю.

А чи я си не газдиня,
Чи не видят люди,
Моя хата не метена,
Юж то тиждень буде.

Прийшли жиди з Добромиля,
Сміття купувати,
Дають мені купу срібла,
Я не хочу брати.

Не буду я замітати,
Буде сміття більше,
Прийдуть жиди з Королівки,
То заплатять ліпше.','[''pisni.org.ua'', ''cat:kolomyyky'', ''cat:lemkivski'', ''Коломийки'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2154293'), datetime('now')),datetime('now'));
