INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2154498','Дружба я си дружба','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Kulik A., Pleśniak P. Dla Oli na słowiańską nutę. Wybrane pieśni łemkowskie, bojkowskie, słowackie, polskie i inne. - Mińsk Mazowiecki, 2001. – 16 p.',NULL,'Дружба я си дружба,
А капелюха не мам,
Часи ся змінили,
Гей, а і люди з ними.

Часи ся змінили,
А ми ся постарили,
А нами керує,
Гей, як вітер задує.

Заграйте ми, гуслі,
Гей, заграйте ми, баси,
Най си витанцую,
Гей, свої младі часи.

Мої млади часи,
Гей, заграйте ми, баси,
Мої младі літа,
Гей, не зазнали світа','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2154498'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2154498','Дружба я си дружба','Дружба я си дружба,
А капелюха не мам,
Часи ся змінили,
Гей, а і люди з ними.

Часи ся змінили,
А ми ся постарили,
А нами керує,
Гей, як вітер задує.

Заграйте ми, гуслі,
Гей, заграйте ми, баси,
Най си витанцую,
Гей, свої младі часи.

Мої млади часи,
Гей, заграйте ми, баси,
Мої младі літа,
Гей, не зазнали світа');
