INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2154251','Ой, летіли гусоньки','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Kulik A., Pleśniak P. Dla Oli na słowiańską nutę. Wybrane pieśni łemkowskie, bojkowskie, słowackie, polskie i inne. - Mińsk Mazowiecki, 2001. – 16 p.',NULL,'Ой, летіли гусоньки низько понад стріхи,
Ой, не єден парубок робить з мене сміхи.
Не за то ся сміє, ніяка шумна дівка,
Але за то ся сміє, жо му не фраїрка.

Ой, парубче, парубче, курка тя задопче,
Ані єдна дівчина в селі тя не схоче.
І як я не схочу, нігде м не хотіла,
Я такими дурнями хлопи городила.

Ой, не треба мі брати, чіпати руками,
Ой, бо ми їх виперут баби язиками,
Не Лемко ти баби, але і не вісти,
Ой, та марно стараютси - мої сльози чисті.','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2154251'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2154251','Ой, летіли гусоньки','Ой, летіли гусоньки низько понад стріхи,
