INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2154420','Буде ярмарок','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Kulik A., Pleśniak P. Dla Oli na słowiańską nutę. Wybrane pieśni łemkowskie, bojkowskie, słowackie, polskie i inne. - Mińsk Mazowiecki, 2001. – 16 p.',NULL,'Буде ярмарок, буде в Пряжові в середу,
Та я свою жену на ярмарок поведу.
Кедь буде дорогу, продям тя, небого,
Кедь буде затано, пойдь дому, газдине!

Нескоро ж ми прийшли, юж ся розходжали,
А за мою стару мало мі давали,
Єден мі обіцяє пів таляра,
Другий ані скілько, бо є дуже стара.

В Пряжові не найшли купця богатого,
Поведу тя, жено, аж до Гуменного.
Кедь тя добре продам, а же нич не втрачу,
Куплю собі ліпшу, хоч дещо доплачу.

Жену я  там продаю, але і заплакаю,
Хто мі тепер буде мої керпці латати?
Піду знов на ярмарок, куплю тя, небого,
Чи будеш затаньо, або за дорого!','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2154420'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2154420','Буде ярмарок','Буде ярмарок, буде в Пряжові в середу,
Та я свою жену на ярмарок поведу.
Кедь буде дорогу, продям тя, небого,
Кедь буде затано, пойдь дому, газдине!

Нескоро ж ми прийшли, юж ся розходжали,
А за мою стару мало мі давали,
Єден мі обіцяє пів таляра,
Другий ані скілько, бо є дуже стара.

В Пряжові не найшли купця богатого,
Поведу тя, жено, аж до Гуменного.
Кедь тя добре продам, а же нич не втрачу,
Куплю собі ліпшу, хоч дещо доплачу.

Жену я  там продаю, але і заплакаю,
Хто мі тепер буде мої керпці латати?
Піду знов на ярмарок, куплю тя, небого,
Чи будеш затаньо, або за дорого!');
