INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2154550','Ой Ченчику-Васильчику, посію тебе в городчику','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'1. Ой Ченчику-Васильчику,
Посію тебе в городчику.          | 2

2. Буду я тя шанувати,
По тричі рази на день вливати.   | 2

3. По тричі рази на день вливати,
