INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2156515','Два півники','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Учбовий репертуар дитячих музичних шкіл, Київ "Музична Україна" с.72',NULL,'Два півники, два півники
Горох молотили,
Дві курочки-чубарочки
До млина ходили.

Цап меле, цап меле,
Коза посипає,
А маленьке цапенятко
Ківші одбирає.

Відміна:
Два півники, два півники
Горох молотили,
Дві курочки-чубарочки
До млина носили.

Цап меле, цап меле,
Коза засипає,
А маленьке козенятко
На скрипочку грає.

Танцюй, танцюй, козуленько,
Ніженьками туп, туп,
Татусенько з матусею
Надеруть нам круп, круп.

А вовчик-сірячок
З лісу виглядає,
Ухопив він козенятко
Та й далі тікає.

Як узяв старий цапок
Новенькії віжки,
Одібрав він козенятко,
Залигав за ріжки.

Хоч вовчик обідрав
Цапові реберце,
Зате в тата з матусею
Радується серце','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:narodni'', ''Дитячі пісні'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2156515'), datetime('now')),datetime('now'));
