INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2155096','Моїй Україні','Музика: Олена Мельник Слова: Олена Мельник. Виконує: Наталія Валевська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Чорний птах розправив крила,
Біль і смуток полонили.
Україну, мов дівчину,
Обійма печаль.
Розділю печаль з тобою
І нехай над головою
Білим птахом відлітає
У блакитну даль!

Приспів:
Я нікому не віддам твою весну,
Край зелений і незайману красу,
Дикий ліс, квітучий яблуневий сад,
Тиху велич переплетених Карпат!
Україна - моя радість і журба,
Моя тиха, віком стомленна сльоза.
Ми разом з тобою будемо завжди,
Моя пісне, білим голубом лети.

Ланцюгом могутнім гори
Затягли її простори,
Україна, мов дитина,
Притулилася.
Зачароване красою
І блискучою росою
Жовте сонце охоронцем
Зупинилося.

Приспів.

Україна - моя радість і журба,
Моя тиха, віком стомленна сльоза.
Ми разом з тобою будемо завжди,
Моя пісне, білим голубом лети.','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2155096'), datetime('now')),datetime('now'));
