INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_215828','Святая Варвара Церков будовала','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Службоньку служив Слізоньку вронив. Святая Варвара Церков будовала. А чи мені Господь дав чи Свята Варвара. День св. Варвари, 17 грудня н.ст., — як 27-ий другого, Щедровечірнього, тижневого кола, — є днем особливих реліґійних і філософійних міркувань на теми астрологічні. Листки з приводу цієї Пісні: Передріздвяний Святочний час: Упереджуючі знаки, Михайла 21.11. Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. День реліґійно-філософських роздумів на Астральні теми, Варвари 17.12 Стежки до листків про Українські традиції. Рокове Коло.','Святая Варвара Церков будовала

Приспів: Радуй ся радуй ся Земле
І Ти Сине Божий нам народивсь

Церков будовала й з Трьома верхами
Й з Трьома верхами й з Трьома окнами
В Перше оконце засвітило Сонце
А в Друге оконце Ясен Місяць світить
А в Трете оконце Янголї щебечуть
Янголї щебечуть Слїзоньками плачуть
Де Слїзонька впала там Криниця стала
В ті Криниченцї образ обявив ся
Образ обявив ся Йсус Христос родив ся
А ми веселїм ся Христу уклонїм ся','[''pisni.org.ua'', ''cat:kolyadky'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_215828'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_215828','Святая Варвара Церков будовала','Святая Варвара Церков будовала

