INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2158022','Їхали козаченьки','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,'Підбір акордів: ofstg','F/C/F/A/A7/Dm/Am/E/Am (2)
Їхали козаченьки
Степом-долиною,
Та й зустріли дівчиноньку
З русою косою.
Приспів:
Коса в''ється до пояса,  |
F              A/A7
В''ється за плечами,     |
Поїхали, дівчинонько,   |
З нами козаками!        |  (2)
Програш:
F/C/F/A/A7/Dm/Am/E/Am
Отвічала їм дівчина:
Їхати не буду,
Я свойого коханого
Повік не забуду!
Приспів.
Прийди, прийди, мій коханий,
До рідної хати!
Там зустріну його я
Та ще й рідна мати.
Приспів.
Там зустріну його я,
Щиро усміхнуся,
Добрій матері старенькій
Низько поклонюся!
Приспів.
Коса в''ється до пояса,  |
В''ється за плечами,     |
Поїхали козаченьки      |
Без дівчини самі!       |  (2)','[''pisni.org.ua'', ''cat:kozacki'', ''cat:narodni'', ''Козацькі пісні'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2158022'), datetime('now')),datetime('now'));
