INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_21550','Ми голуба ізловили','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. А вже весна скресла. Збірник гаївок. - Львів, 2003. 2. Народні співи Галичини. Гаївки. / Зібрав та впорядкував Михайло Мишанич. - Львів: Ґердан, 1991. С. 62.','Опис гри: Вибирають хлопця і дівчину, беруться за руки довкола них. Коло іде в один бік, пара — в інший. Після закінчення пісні хлопець вибирає замість себе дівчину з кола, дівчина — хлопця, а самі приєднуються до кола. Нова пара береться за руки, і все повторюється від початку.','Ми голуба ізловили,
Всі довкола обступили:
"Ой голубе, чого тужиш?    |
Вибирай си, кого любиш."   |(2)

"Я ходила вибирала —       |
Нема того, що-м кохала.    |(2)

Нема, нема і не буде,
Розсудили лихі люде,
Розлучили, розсудили,      |
Щоб ми в парі не ходили".  |(2)

Твої браття говорили,
Щоби ми ся не любили.
Твої сестри зневажали,     |
Щоби ми ся не кохали.      |(2)

А ми в парі ходить будем   |
І друг друга любить будем. |(2)    Мелодія для 1 і 2 голосу','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_21550'), datetime('now')),datetime('now'));
