INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2157961','Дзвенить у зорях небо чисте','Музика: Олександр Білаш Слова: Дмитро Павличко. Виконує: Тріо Байко, Анатолій Мокренко, Лариса Остапенко','uk','ukraine_1991',NULL,NULL,'Радiо 1, 21.12.2009 ("Рiднi наспiви")','Був дуже здивований, що цiєї чарiвної пiснi у вас досi немає. Її багато хто виконував. Надсилаю mp3 у виконаннi трiо Нiни, Марiї та Данiїли Байко. З повагою - Andrew','Дзвенить у зорях небо чисте,
Палає синім льодом шлях.
Неначе дерево безлисте,
Стоїть моя душа в полях.

Як надійшла щаслива доля,
Збудила весняну снагу,
Душа моя, немов тополя,
Зазеленіла на снігу.

Як надійшла любов справдешня,
Хлюпнула пригорщу тепла,
Душа моя, немов черешня,
Понад снігами зацвіла.

Як надійшла, як засіяла
Та дружба, що живе в літах,
Душа моя над снігом стала,
Неначе яблуня в плодах','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2157961'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2157961','Дзвенить у зорях небо чисте','Дзвенить у зорях небо чисте,
