INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2159055','Журавлі **','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'Фольклорний архів ансамблю "Божичі". Запис в с.Межирич (Маврино) Павлоградського р-ну Дніпропетровської обл. 12.08.1993 Касета 3',NULL,'В тихім небі осіннім, туманнім
Журавлі, журавлі, журавлі.
Може бути колись вони сядуть
У моєму далекім селі.

Журавлі, друзі милі, хороші,
Як будете в моєму краю,
Я вас прошу: не в службу, а в дружбу
Розшукайте дівчину мою.

А, як вечір багряно-червоний
Розіллється в далекій далі,
Передайте привіт і від мене
Всій моїй українській землі','[''pisni.org.ua'', ''cat:arkhiv-bozhychi'', ''Фольклорний архів анс. "Божичі"'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2159055'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2159055','Журавлі **','В тихім небі осіннім, туманнім
Журавлі, журавлі, журавлі.
Може бути колись вони сядуть
У моєму далекім селі.

Журавлі, друзі милі, хороші,
Як будете в моєму краю,
Я вас прошу: не в службу, а в дружбу
Розшукайте дівчину мою.

А, як вечір багряно-червоний
Розіллється в далекій далі,
Передайте привіт і від мене
Всій моїй українській землі');
