INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2157512','Серед лісу, лісу списів і мечів','Українська народна пісня. Виконує: Остап Кіндрачук','uk','ukraine_before_1917',NULL,NULL,'Кубанські кобзарі','* Джанхот - кубанське поселення на березі Чорного моря. ** Хеджрети - черкеські бойовики.','Серед лісу, лісу списів і мечів
Їде полк козаків-вусачів.
Попереду осаул молодий              |
Веде сотню відчайдухів прямо в бій. | (2)

