INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2159091','Ой, вербиченько','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'Фольклорний архів ансамблю "Божичі". Запис в с.Межирич (Маврино) Павлоградського р-ну Дніпропетровської обл. 12.08.1993 Касета 3',NULL,'Ой, вербиченько-чарівниченько,
Не смути моє біле личенько.

Ой, ти зіронька, зоре ранняя,
Ждала милого до світання я.

Заквітчалась я зелен рутою,
Щоб не краялось серце смутою.

Понад садом йшла, зажурилася,
Десь любов моя забарилася','[''pisni.org.ua'', ''cat:arkhiv-bozhychi'', ''Фольклорний архів анс. "Божичі"'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2159091'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2159091','Ой, вербиченько','Ой, вербиченько-чарівниченько,
