INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2159212','Молодії молодиці','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'Фольклорний архів ансамблю "Божичі". Запис в с.Межирич (Маврино) Павлоградського р-ну Дніпропетровської обл. 12.08.1993 Касета 3',NULL,'Молодії молодиці,
Молодії молодиці
Всі гуляють із вечора
На вулиці!

А у мене чоловіще,
А у мене чоловіще
Не пускає на вулицю
На ігрище.

А я його одурила,
А я його одурила:
Не в поливанім горшку
Борщ зварила.

Борщ зварила, не зам''яла,
Борщ зварила, не зам''яла,
Сама пішла на вулицю,
Погуляла.

Та й недовго я гуляла,
Та й недовго я гуляла,
Поки зірка світова
Загорала.

Де ж ти, мила, так гуляла,
Де ж ти, мила, так гуляла,
Що вже зірка світова
Загорала?

Там корівка отелилась,
Там ягничка окотилась,
Біля них я, мій миленький,
Забарилась.

Пішов милий провіряти,
Пішов милий провіряти,
Аж немає ні теляти,
Ні ягняти.

Пішов милий на долину,
Пішов милий на долину
Та й вирізав собі
Гарну хворостину.

Більш не буду я дурити,
Більш не буду я дурити,
Буду добрий борщ
Миленькому варити','[''pisni.org.ua'', ''cat:arkhiv-bozhychi'', ''Фольклорний архів анс. "Божичі"'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2159212'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2159212','Молодії молодиці','Молодії молодиці,
