INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_21573','Вінку ружовий','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'А вже весна скресла. Збірник гаївок. Львів, 2003.','Хлопці і дівчата утворюють коло і співають. В середину кола стає один з учасників гри ("ружовий вінок"), який під кінець співу вибирає собі пару. Тепер той (та), кого вибрали, залишається в колі, попередній "вінок" примикає до кола. Гра повторюється з початку, і так —довільне число разів.','Gm
"Вінку ружовий,
Gm
Десь був?" — "У Львові".

Cm
"Що за тя давали?"
D
"Сто золотих червоних" —

"А мій милий Тимку,
Вибирай си дівку!

D
Котру хоч,
Gm
То підскоч!"','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_21573'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_21573','Вінку ружовий','Gm
