INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2159165','І сюди гора','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'Фольклорний архів ансамблю "Божичі". Запис в с.Межирич (Маврино) Павлоградського р-ну Дніпропетровської обл. 12.08.1993 Касета 3',NULL,'І туди гора, сюди гора
Та все кам''яная.
Ой, куда їдеш-уїжджаєш,
Любов дорогая?

Та куда їдеш-уїжджаєш,
Сизокрилий орле?
Ой, хто ж мене молодую
В цей вечір пригорне?

Та пригортайся, моя мила,
Другому такому.
Та й не кажи тої правди,
Що мені одному.

Та зеленеє жито жала,
Снопів не в''язала,
Та ж скільки хлопців не любила,
Правди не казала.

Ой, тоді снопи зав''яжу,
Як сонечко зайде,
Ой, тоді я правду скажу,
Як рученьки зв''яже','[''pisni.org.ua'', ''cat:arkhiv-bozhychi'', ''Фольклорний архів анс. "Божичі"'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2159165'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2159165','І сюди гора','І туди гора, сюди гора
Та все кам''яная.
Ой, куда їдеш-уїжджаєш,
Любов дорогая?

Та куда їдеш-уїжджаєш,
Сизокрилий орле?
Ой, хто ж мене молодую
В цей вечір пригорне?

Та пригортайся, моя мила,
Другому такому.
Та й не кажи тої правди,
Що мені одному.

Та зеленеє жито жала,
Снопів не в''язала,
Та ж скільки хлопців не любила,
