INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_215890','Візьму я коновку','Українська народна пісня. Виконує: Алла Опейда, В''ячеслав Судима','uk','ukraine_before_1917',NULL,NULL,'Аудіо-CD - Алла Опейда, В’ячеслав Судима. "Повстанскі та стрілецькі пісні (60-річчю УПА присвячуєтся)."','Записано на слух з аудіо.','Візьму я коновку
Та й піду по воду,
А там хлопці-риболовці,      | (2)
Хлопці з козацького роду.    |

