INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_21596','Коструб','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'А вже весна скресла. Збірник гаївок. Львів, 2003.',NULL,'Бідна моя головонько,
Нещаслива годинонько!
Що-м я собі наробила,
Що Коструба не злюбила!?
Устань, устань, Кострубоньку,
Станем рано до шлюбоньку.
Рано, рано пораненьку,
На білому каміненьку.

Діалог дівчини з подругами:

— Христос воскрес!
— Воїстину воскрес!
— Чи не виділисте мого Коструба?
— Слабий!

Дівчата знов співають: "бідна моя головонька".
Потім в діалозі замість "слабий" дівчата кажуть
"вмер, вже повезли на цвинтар". А далі:

Слава тобі, Божий Царю,
Що мій Коструб на цвинтарю.
Лежи, лежи, як колода,
Я молода, як ягода,    (2)
А й мене для тебе шкода!
Лежи, лежи, щобись не встав,
Щоб до мене другий пристав,
Рученьками заплескала,
Ноженьками задоптала.     Основна мелодія','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_21596'), datetime('now')),datetime('now'));
