INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_215952','Ой там за Горою та за Кам’яною','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','РОЗСПІВ: Ой- там- за- Го-ро-ю- та- за- Ка-м''я-но-ю- Щед-рий- Ве-чір- До-о-об-рий- Ве-чір- Колядка стародавня: Українське Різдво Світа. Буде в Тебе Господь на Вечері. Радуйся Земле Коляда іде! Ой Там виxодило та Три Товариші. Будуть до Тебе з Неба Гості. Три Свічі палало Три Святі читало. Будять же Тебе аж Троє Гостей. На Вашім Мості Троякі Гості. Чим ся похвалиш. Ой ходили та блудили Три Коляднички. Просит Боженька на Вечерейку. Сподіваймо ся а Трох Гостеньків. Троє Гостей Троє Радостей. Тогди пізнали Господа Бога. В Нашего Брата а в Єго Дворі Встань Господарку довго не лежи Гай з Містонька Судомиренька Гей здоров же був Наш Господарю Добрий Вечір Тобі Гречная Родино Добрий Вечір Тобі Пане Господарю Радуйся (1) Добрий Вечір Тобі Пане Господарю Радуйся (2) Здибаў сьі Місьіць йа з Дрібним Дошчом На Святе Різдво тай на Рождество Ой дай Боже ой за Горою за Високою Ой там за Горою та за Кам''яною Ой треба треба Дощу треба Ой у Нашого Господарентя Ой ходили та блудили Три Коляднички Ой чи Ви спите Господареньку Пан Господар уставай с Постелі Пане Господару а на Твоїм Двору Пане Господару вставай с Постелі Пане Господарю вставай з Постелі Пане Господарю вставай з Постелі (2) Святи Боже Вечероньку Стоїть же стоїть Нова Світлонька Уставай Пане Пане Господаре Чи є чи нема Ґосподар Дома Чи є чи нема Пан Сподар в Дома Я в цего Ґазди Білії Двори Чи Дома Дома Пан Господар. А чи вдома Пан Хазяїн А чи Дома Дома Пан Хазяїн Господарський Двір на Семи Стовпах Ой Добрий Вечір Пане Господарю ми в Тебе Ой чи є чи нема Пан Господар Дома Ци Дома Дома Білий Молодче Ци Ти Дома Гречний Пане Чи в Дома вдома Господар дума Чи Дома Дома Господаренько Чи Дома Дома Микола Дома Чи Дома Дома Пан Господар Чи Думу дума Пан Господар (1) Чи Думу дума Пан Господар (2) Чи є чи нема Господар Дома Чи є чи нема Ґосподар Дома Чи є Дома Пан Господар Чи є чи нема Пан Сподар в Дома Щедрий Вечір Добрий Вечір Чи вдома вдома Пані Бабуня. Чи вдома вдома Пані Бабуня Чи Дома Дома Бідная Вдова. Була Вдовойка в Конець Села Чи Дома Дома Бідная Вдова Ідея Бога на Свят-Вечер. Народна Віра в Бога. Українська Астрально-мітольоґічна реліґійна концепція. Невиразність ідеї Господа на Свят-Вечер спричинена оцією важною обставиною, що на неї зложився цілий комплекс реліґійних ідей, нагромаджених народом у часі його довговікової культурно-історичної еволюції. Такий спліт ідеольогічний, цілий світ реліґійних ідей, міститься в Астрально-мітольоґічнїй реліґійній концепції, яка поезією й багацтвом з''ображень полонює на Свят-Вечер всю психіку Українського народу. В суті річи Астральна реліґія в Українського народу поглиблює ідею Бога і змірює до Його звеличання; але рівночасно розбиває вона реліґійні поняття народу на окремі образці, які поодиноко притягають його увагу так, що він через них забуває деколи про головну ідею Бога. Найвизначнішими Астрально-реліґійними ідеями на Свят-Вечер приявляються оці: 1) Небесна Трійця, яка виступає в двоякім виді: Місяць, Сонце і Дощик, або Місяць, Сонце і сам Господь, — і є властиво шануванням Господа в Астральній ґльорії; 2) Астральна Трійця, що є символом Астральним попередньої — і 3) Астральна Двійця: Місяць і Зоря як Божі післанці до народу. Як Астральну Двійцю і окремий об''єкт можна б уважати Місяць і Сонце в Небесній Трійці. Всі тоті Небесні ґрупи з''ображують символічно Господа, котрого всією душею і серцем прагне нарід видіти гостем у себе на Свят-Вечер і на Тайній Вечері. Оця-то містична гостина має народові принести щастя і добро і взагалі — спричинити обнову земного світа і людського життя. Докладіше у статтях "Бог в Астральній славі", "Символіка в Святочних обрядах і стравах", "Бог, Місяць і шанування часнику у Староукраїнській традиції", які додано у форматі PDF на сторінці Українські свята Різдва Світа і Щедрого Вечора. (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) Листки з приводу цієї Пісні: Світ Різдва-Коляди — Храм Українських і загальнолюдських мрій. Святий Вечер 6.01 — властиве Свято Різдва-Коляди. Свята, Тайна, Вечеря 6.01 — Як її підготувати і що вона означає? Українська Астрально-мітольоґічна реліґійна концепція. Бог, Різдво Світа, Дідух і Лицарі. День реліґійно-філософських роздумів на Астральні теми, Варвари 17.12. Українські релігійні роздуми про Бога: Яблучко. Стежки до листків про Українські традиції.','Ой там за Горою та за Кам''яною

Приспів:
Щедрий Вечір Добрий Вечір!

Ой там виxодило та Три Товариші
Що Перший товариш Ясне Сонце
А Другий товариш Ясен Місяць
А Третій товариш Дрібен Дощик

Що Сонечко каже як я зійду
То зрадується Старе й Мале

Місяць каже як я зійду
То зрадується весь Звір у Полі
Ой Звір у Полі Чумак у Дорозі
Чумак у Дорозі Хазяїн у Домі

Дощик каже як я зійду
То зрадується Жито і Пшениця
Жито і Пшениця і всяка Пашниця','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:krasa-pryrody'', ''cat:shchedrivky'', ''Колядки'', ''Пісні про красу природи'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_215952'), datetime('now')),datetime('now'));
