INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2159614','Вдова Галя','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'Фольклорний архів ансамблю "Божичі". Запис в с.Межирич (Маврино) Павлоградського р-ну Дніпропетровської обл. 22.04.1992 Касета 5',NULL,'Ой, як жила вдова,
Жила на подолі
Та й не мала вдова
Ні щастя, ні долі.

Тільки мала вдова
Дев''ять синів з роду,
Дев''ять синів з роду,
Десятую дочку.

Та й тую віддала
В чужу стороночку,
В чужу стороночку
Та й за крамарочку.

Як поїхав крамар
У Крим торгувати
Та взяв собі Галю
Йому помагати.

Ой, де ж узялися
Дев''ять розбіяків,
Ой, крамара вбили,
А Галю схопили.

То що старший каже:
Треба її вбити,
А найменший каже:
Треба розпросити.

Ой, скажи ж ти, Галю,
Якого ти краю?
А я краю, краю,
Краю долиного.

А я краю, краю,
Краю долиного,
А я роду, роду,
Роду вдовиного.

Браття мої, браття,
Що ж ми наробили:
Ой, ми сестру Галю
Мало не убили','[''pisni.org.ua'', ''cat:arkhiv-bozhychi'', ''Фольклорний архів анс. "Божичі"'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2159614'), datetime('now')),datetime('now'));
