INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_215910','В Саду Садочку Вишня стояла','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) ― Весілля: Дівич-Вечір... Великдень... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива... Рокове Коло. Українські реліґійні роздуми про Воскресіння, Неволю і Спасіння. Пісні-плачі Сокола-Прадіда. 1 Рай Рождество Вишня стояла. — Наче йде розмова з Різдвом, Рай-Рождеством. 2 Вгору піднявся Богу молився. — Сам Господь Біг молиться! А люди Його наслідують: порівняти з теургічним підходом, приміром у кабалістів або в активному символізмі неоплатоніків. Розспів: В Са-ду- Са-доч-ку- Виш-ня- сто-я-ла- Ра-ай- Рож-де-ство- Виш-ня- сто-я-ла- Джерела: 1. Радуйся, Земле, Коляда їде! Автор-упор. Ярослава Музиченко. Ред., муз.ред. Катерина Міщенко. Худ. Олена Гайдамака. Київ, "Смолоскип" 2000. 152с. — 2. Ксенофонт Сосенко. Культурно-історична постать Староукраїнськиx Свят Різдва і Щедрого Вечора. Львів, 1928. СІНТО, Київ 1994. 343с. Богу молився щоб Світ творився. За Цим Словом будьте здорові! В Саду Садочку Вишня стояла За Ворітьми за Праворітьми З Збором ідемо Полон несемо Красная Панна Сад садила Ми си изийшли в Вашим Домочку Орала би ся Золота Гора Прилетіли Щебетоньки Славен єс Боже по всему Сьвіту Три Гискри впало Три Морі стало. Буде в Тебе Господь на Вечері. Ой Ми зіслані на признаванє. Радуйся Земле Коляда іде! А з Полянойки до Царинойки. Садило-садило Богу ся молило. Мольме ся Богу і всі посполу. Листки з приводу цієї Пісні: Шанування Творця і Господа Світа. Українські релігійні роздуми про Бога. Колядки про Почин Світа. Первовічне Дерево і ідеал духового Творця Світа. Передріздвяний Святочний час: Упереджуючі знаки, Михайла 21.11. Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Стежки до листків про Українські традиції. Рокове Коло. Пояснення Колядок про Різдво, Вогонь і Воду: Українське містичне Весілля. Ця Колядка співає про покликану Господом творчу силу Вогню в сполуці з Водою. Див. також: Пане Господаре на твоїм Двору Ялина стоїть Три Іскри – Три Моря: Містична злука Вогню з Водою. Годі зобразити більше поетично містичну сполуку Вогню з Водою і її творчу силу. В цій Колядці виступають Вогонь і Вода дійово, як Первовічні два начала, з котрих Вогонь був першим і своєю вдаряючою творчою Силою викликав начало друге Воду — і разом з нею став орудником Божих Світотворчих починань. Що це за Іскри з містичної Трійці, з Райського Дерева, чи Прадерева? — Ми впізнаємо в Колядках про Почин Світа тоту саму троєпальну Трійцю: вона сплила з Райським Деревом на Землю. Воскова горіюча трійця, яку ми знаємо з Українських Різдвяних Свят та з Йорданських Водорщів, — це її символ, а мітольоґічна Трійця на Райськім Дереві — це Три Небесні Світила: Місяць, Сонце і Зоря, про яких співають Колядки, що їх принесло Первовічне Дерево пливучи по Первовічних Водах. Це Астральний творчий вогонь, про який була бесіда повище. Він у сполуці з Водою був творчим чинником у Почині Світа. Ідея Почину Світа і Його Творця. Колядки як Міти про Почин Світа, Первовічне життя. Бог і Пара Вогонь/Вода. Ідея наглядно виступає — Вогонь як животворна Троїста Сила, будить життєве тепло у Всесвіті і рівночасно покликує до дії творчу Воду. Сам Господь у тій Воді купається — така вона свіжа й животворча. Мабуть чи не сам Господь є символом того Первовічного Вогню і навпаки — Вогонь символом Господа (ідея відома з мітольоґії світової і біблійної). В кожнім разі на цих сполучених двох Первовічних елементах стає "Престіл" Божої слави й основа благословенства Божого людям. Українське містичне Весілля. Ось Українське містичне Весілля: Вогню й Світла — з Водою; про яке згадують у мітольоґічній, пізнішій культурно-історичній формі — Вавилонці. Тут можна наглядно ствердити ріжницю в культурній позиції ідей Українських і Вавилонських. Український Світотворчий міт як найдавніший. При тім — оця ідилія взаємин людини з Господом: оця зворушлива пошана й довірчивість Господа до "пана господара", це свідоцтво первісних людських почувань і думок, традиція найстарших людських переживань і також доказ, що Український міт про Світотворчу сполуку Вогню й Води є одним з найдавніших. Про ідеольоґію Різдва і Щедрого Вечера. Ідея про творчу силу Вогню і Води є однією з основних в ідеольоґії Різдва і Щедрого Вечера; а зрозуміння цієї містерії дасть ключ розуміння інших культурно-реліґійних явищ в обох Святах. Її зрозуміння устійнює також думку, що провідною ідеєю Свята Різдва є Сотворення Світа, котру Щедрий Вечер відтак доповнює. Основа Староукраїнської мітольогії й реліґії. Різдвяна ідея та Різдвяна містика з Вогнем і Водою, оперта на Астральнім шануванні, є властиво основою всієї Староукраїнської мітольогії й реліґії. Передріздвяна та Передщедровечірня символіка. Передріздвяне та Передщедровечірнє коло тижнів є переповненим символікою в напрямі шанування Вогню й Води. Особливо вдаряючою є символіка Астральної Сили Вогню, а особливо Сили Місяця. На початку оба кола тижнів, — Різдвяний і Щедровечірній, — немов переплітаються символікою Місячною; шанування Місяця горує над іншим шануванням цілий час. Колиж прийде Різдво, лунає більша частина Колядок піснями про Водицю, Росицю, Дунай і т.і., а на Щедрий Вечер приходить величаве Свято Води. Астральне шанування лучиться тоді з шануванням Води. Колядки і Щедрівки оспівують Вогонь святощію. Особливо ж виходить це ясно з Колядок і Щедрівок, що оспівують Вогонь святощію, співають про чудотворні Іскри злучені з Водою, співають про три мітичні Вогні, вступаючі в двір ідеального Господаря; величають Росицю з Неба, мітичну Керницю, мітичний Дунай, Море з Сліз Господа, — та вважають їх за містичні, творчі й благодатні сили, а сполуку вогню й води все за містерію, що приносить добро і щастя. Спогади про Праводу та життєві ідеали. Український нарід лучить із Святоріздвяними спогадами про Праводу цілий світ своїх життєвих ідеалів, що їх сподіється здійснити при містичній чудотворній помочі тої Води, через яку стався увесь Світ. Її сила і святість немов степенується в Святочнім часі від Різдва до Богоявління (Водорщів) та доходить до зеніту в великій містерії Водорщів. Майже кожна Колядка й Щедрівка нагадує народові про мітичні, незглубимі таїнниці Світових Вод. Містична купіль Господа. В Колядках містична купіль Господа приносить світові щастя і добро. Це є первовічна містерія, — благословенні цією купіллю Води служать до освіження й обнови Новонародженого Світа, наче поправляють його хиби й недостачі та запобігають недолі народу. Сокіл (або янгол) виплакав у Бога добру Долю людям. В інших Колядках сказано, що Господь плаче прийшовши між нарід і з його сліз творяться животворні води. Ім''я Господа буває в Колядках синонімом Христа, Спасителя світа, що визволяє людий від вічної недолі. В цей спосіб стається Сокіл, який плаче, в очах народу алеґоричною поставою Спасителя навіть при християнькім світогляді. Храм Українських і загальнолюдських мрій. Сильна особистість Українського народу. (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.)','В Саду-Садочку Вишня стояла
Приспів за зразком:
Рай Рождество Вишня стояла(1)

Вишня стояла Свічка палала
Свічка палала Іскра упала
Іскра упала Озерце стало
А в тім Озерці сам Бог купався
Сам Бог купався в ризи вбирався
В ризи вбирався вгору піднявся
Вгору піднявся Богу молився(2)
Богу молився щоб Світ творився!','[''pisni.org.ua'', ''cat:kolyadky'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_215910'), datetime('now')),datetime('now'));
