INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2158114','Пісня про Олену Степанівну','Українська народна пісня','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'похідний співаник "Маківка" - Івано-Франківськ, 2005 р.',NULL,'Прощавай, мій рідний краю,
Моя Україно!
Прощай, саде, саде-винограде,
Молода дівчино!

Бо я їду в степ широкий
Слави здобувати,
І та й про тебе, моє серденятко,
Буду споминати!

Ой, у горах, у Карпатах,
Там вітер лютує.
Б''ються стрільці на горі Маківці,
Аж ся світ дивує!

А Олена Степанівна
Ранених курує,
Вона рани, рани промиває
Та ще й бандажує.

Бандажує й завиває
Стрілецькії рани,
Ой, то була гарна Степанівна,
Ще краща від мами!

Гарна її мати була,
На світ породила,
Що Олена Степанівна
Свій край боронила!

Ой, у горах, у Карпатах,
Там вітер лютує.
Б''ються стрільці на горі Маківці,
Аж ся світ дивує!','[''pisni.org.ua'', ''cat:strilecki'', ''Стрілецькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2158114'), datetime('now')),datetime('now'));
