INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_215971','Святи Боже Вечереньку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа. Буде в Тебе Господь на Вечері. Ой там виxодило та Три Товариші. Ідея Бога на Свят-Вечер. Народна Віра в Бога. Поєднання реліґійних світоглядів у Колядках. Нема Колядок чисто народних, в яких не було би комбінації реліґійної ідеольоґії у її культурно-історичній еволюції, почавши від пракультурної доби. Ось приклад одної з Колядок з характером, — на перший погляд, — новішим, а в суті річи давньої. У цій Колядці виступає асоціяція двох, а властиво трьох реліґійних світоглядів. Бо коли перша половина Колядки приявляє Бога в таких ідеально-сердечних взаєминах з господарем, які можна собі уявити хіба в пракультурних обставинах людського життя і за часів пракультурної безоглядної віри в Бога, — а при тім лучить первісну реліґійну ідеольогію з християнською, — то друга частина Колядки, а властиво її кінець, бере цілий образець в Астральну ґльорію і натякає на Астрально-мітольоґічні ідеї. Можна подивляти оцю ніжність і артистичний такт народу, що так обережно і заразом справно годить одні реліґійні ідеї з другими. А в Горі в Горі в Глибокім Зворі А в Нашого Дядька да в Його Дому Святий Вечір А в нашого Пана Отця Золотії Ворітця А в Нашого Хазяїна тай Ворота Нові А в Пана в Пана в Пана Івана Святий Вечір А в Пана Йвана Золота Верба А в Полі в Полі Cам Плужок оре А в тій Хаті як у Раю А всі Святії ослоном сіли В цьому Дворку як у Вінку! В цьому Домі як у Раю Господарський Двір на Семи Стовпах Да чому ти Дівчино гуляти не йдеш Добрий Вечір Тобі Гречная Родино Добрий Вечір Тобі Пане Господарю Радуйся (1) Добрий Вечір Тобі Пане Господарю Радуйся (2) Добрий Вечір Щедрий Вечір За Горою за Крутою Защебетала гей Ластівонька Ішов перейшов Місяць по Небу Й а в Лісі в Лісі й а в Медоборі Йшов Місячейко попід Небойка Колєд-Колєдиця на Покутті Кутиця Маладий Бог Тебе кличе Светий Вечер На Горі Горі Топірцї Дзвенї Ой в Ліску в Ліску Листя на Грабі Ой в Ліску в Ліску на Жовтім Піску Ой в Чистім Поли блисько Дороги Ой Добрий Вечір Пане Господарю ми в Тебе Ой на Горах Огні горять Ой наш Братчику сідай коло Нас Ой позволь Пан Хазяїн нам Колядочку сказать Ой сів Христос вечеряти Ой там за Горою та за Кам''яною Ой у Нашого Господарентя Ой у Пана Хазяїна та на Його Дворі Ой ходив ходив Місяць по Небі Ой ходить бродить Місяць в Хмарі Ой як то було з Початку Світа Ой як то було з Початку Світа Боже Наш Орала би ся Золота Гора Пане Господаре на Твоїм Двору Ялина стоїть Пане Господару а на Твоїм Двору Пану Хозяїну Бог Тебе кличе Святий Вечір Пан Господар уставай с Постелі Прибирай сї Славні Гуспудару Прийшли ми Кумо колядувати до Тебе Прилетіла Ластівочка Прилетіли Щебетоньки Росте Деревко Тонке й Високе Сидїв Никола по Конец Стола Сидять Кравци дай на Лавочціе Славен єс Боже по всему Сьвіту Сьвитий Николай став коло Стола Там у Нашого Пана Сподара У Пана Івана да за Його Сталом Уставай Пане Пане Господаре Xодить походить Місяць по Небу Ци ти вдома Гречний Пане Чи вдома вдома Пані Бабуня Чи Дома Дома Господаренько Чи Дома Дома Пан Господар (1) Чи Думу дума Микола Дома Чи думу дума Пан Господар? Чи Думу дума Пан Господар Чи є чи нема Господар в Дома Чи є чи нема Господар Дома Чи є чи нема Пан Сподар в Дома Чий же то Плужок найранче вийшов Шо у Нашого Пан-Оца Широкії Ворота Щедрик-Щедрик Щедрівочка (1) Щедрик Щедрик Щедрівочка (2) Щедрик Щедрик Щедрівочка (3) Що в Пана Степана по Його Двору Що й у Нашого Пан-Отця Золотії Ворітця Щож нам було з Світа Почитку Боже Наш (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) Докладіше у статті "Бог в Астральній славі. І", яку додано у форматі " PDF " на сторінці Українські свята Різдва Світа і Щедрого Вечора Листки з приводу цієї Пісні: Свята, Тайна, Вечеря. День реліґійно-філософських роздумів на Астральні теми, Варвари 17.12 Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до інших листків про Українські традиції.','Святи Боже Вечероньку
