INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_216111','Чи Дома Дома Пан Господар','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','РОЗСПІВ: Чи- До-ма- До-ма- Пан Гос-по-дар- Щед-рий- Ве-е-чір- Доб-рий- Ве-е-чір- Доб-рим- Лю-ю-дям- на- Здо-ро-в''я! Колядка стародавня: Українське Різдво Світа. Буде в Тебе Господь на Вечері. Ой там виxодило та Три Товариші. Чи Думу дума Пан Господар! Ци Ти Дома Гречний Пане Чи Дома Дома Господаренько Чи Дома Дома Пан Господар Чи Думу дума Пан Господар (1) Чи Думу дума Пан Господар (2) Святочні пісні та нове покоління. Оця праця має за тему Староукраїнську культуру й реліґію, яка приявлюється в давніх передхристиянських Святах — реліґійних, господарських і побутових, що досі тривають в Українського народу в фраґментах давніх обрядів і в зв''язаних з Святочними часами народних Піснях. Хоч зараз велика частина Українського народу, особливо нове покоління, що виросло на повоєнних руїнах, не здає собі справи з провідних думок цих Свят, але інтуіційно відчуває повагу і святість давніх традицій, і все-таки увесь нарід держиться досі Старовіцьких Святочних звичаїв і поведінок. Цю інтуіційну свідомість чогось величного й Святого, переказаного предками і зв''язаного з Старовіцькими обрядами, піддержують злучені з Святочним часом Пісні, — ось як: Колядки, Щедрівки, Гаївки і т. д., — і у них-то найбільше міститься народних традицій, як реліґійних, так господарських і суспільних, поданих у мітичній формі.... Відтворити з тих традицій образ давньої Української віри і культури. Ця Віра триває досі, хоч не є сформульована доґматично, а давня Українська культура є в основах сучасного життя народу. Нарід жиє Старими ідеями; а інтеліґенція народна переходить над ними до порядку денного, не здаючи собі справи з їх культурної ціни і сили, не розуміючи психіки народу і будучи в постійній з ним дисгармонії; не цінить культурного давнього дорібку, який мав колись свою стійкість і міг би бути вихіснуваним і сьогодня, хоч інші зараз життєві й культурні обставини й поняття. (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) Читати листки з приводу цієї Пісні: Ідея Бога на Свят-Вечер. Бог, Різдво Світа, Дідух і Лицарі. Українські релігійні роздуми про Бога: Яблучко. Стежки до інших листків про Українські традиції.','Чи Дома Дома Пан Господар
Приспів: Щедрий Вечір Добрий Вечір!
Добрим Людям на Здоров''я!

А я знаю що Він Дома
Сидить же Він в Кінець Стола
А на Йому Шуба Люба
А на Шубі Поясочок
А на Поясочку Калиточка
А в тій Калиточці Сім Шеляжечків
Сьому-тому по Шеляжечку
А нам Братці по Пиріжечку
А Старим Бабам Паляниці
Щоб плодилися Бики і Телиці
Барани і Ягниці
Скільки Кочечок стільки Дочечок
Скільки Дубочків стільки Синочків','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:philosophic'', ''cat:shchedrivky'', ''Колядки'', ''Філософські пісні'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_216111'), datetime('now')),datetime('now'));
