INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2160063','Вийди, вийди, Іванку','Українська народна пісня. Виконує: Майя Негребецька','uk','ukraine_before_1917',NULL,NULL,NULL,'обробка та аранжування Лесі Соболевської Альбом: Лети, моя співаночко','Вийди, вийди, Іванку,
Заспівай нам веснянку.
Зимували, не співали,
Весни дожидали.

А вже весна, весна скресла,
А що ти нам та й принесла? -
Принесла вам дрібну росу
І дівочу ясну красу.

Дівочая краса, краса,
Як весняная дрібна роса,
На Дунаю прана, прана,
А у меду полокана.

Ой ти, весно, красна.
Зелен-зелен рястом,
Ой ти, весно, пишна
Квіточками вишні.
Принесла нам літечко,
Щоб родило житечко,
Озима пшениця
І всяка пашниця.

Вийди, вийди, Іванку,
Заспівай нам веснянку.
Зимували, не співали,
Весни дожидали.

Ой ти весно, наша весно,
А що ти нам тай принесла? -
Зеленую травиченьку
І зіллячко запашненьке.

Малим дітям - по яблочку,
Старим бабам - по ціпочку,
Коробочку з веретенцями,
Скриню з червінцями.

Усім газдам - по кийочку,
А хлопчатам - по батіжку.
Молодицям - по серпочку,
А дівчатам - по віночку.','[''pisni.org.ua'', ''cat:narodni'', ''cat:vesnyanky-hayivky'', ''Народні пісні'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2160063'), datetime('now')),datetime('now'));
