INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2160550','Соловію','Українська народна пісня. Виконує: Рушничок','uk','ukr_ssr_1919_1991',NULL,NULL,'Надав С.Заставський','Інший, бандерівський варіянт народної пісні "Їхав, їхав, козак містом" Аранжовано "Кладочка, кладочка узесенькая".','Соловію, рідний брате,
Виклич мені дівча з хати.
Та гей, гей.
Виклич мені дівча з хати.
Та гей!

Виклич мені дівча з хати -
Бо я маю щось спитати...
Та гей, гей.
Бо я маю щось спитати...
Та гей!

Бо я маю щось спитати...
Чи не била стара мати
Та гей, гей.
Чи не била стара мати
Та гей!

Ой чи била, чи не  била,
Що з повстанцем говорила
Та гей, гей.
Що з повстанцем говорила
Та гей!

А я мамі признаюся,
Що з повстанцем кохаюся
Та гей, гей.
Що з повстанцем кахаюся
Та гей!','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2160550'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2160550','Соловію','Соловію, рідний брате,
Виклич мені дівча з хати.
Та гей, гей.
Виклич мені дівча з хати.
Та гей!

Виклич мені дівча з хати -
Бо я маю щось спитати...
Та гей, гей.
Бо я маю щось спитати...
Та гей!

Бо я маю щось спитати...
Чи не била стара мати
Та гей, гей.
Чи не била стара мати
Та гей!

Ой чи била, чи не  била,
Що з повстанцем говорила
Та гей, гей.
Що з повстанцем говорила
Та гей!

А я мамі признаюся,
Що з повстанцем кохаюся
Та гей, гей.
Що з повстанцем кахаюся
Та гей!');
