INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2159818','І учора в куми','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'Фольклорний архів ансамблю "Божичі". Запис в с.Межирич (Маврино) Павлоградського р-ну Дніпропетровської обл. 22.04.1992 Касета 5',NULL,'І учера в куми,
І сьогодні в куми,
Ну, а завтра куму
Та й до себе зазву.

Ой, а завтра куму
Та й до себе зазву,
Чим же я ту куму
Угощатиму?

Я найму стрільця,
Хай уб''є горобця.
Ой, тоді я куму
Та й у гості зазву.

І з ніжок, і з крилець
Зварю кумі холодець,
Туловище посічу
Та й в духовці запечу.

А з голови кумі
Буде юшечка,
Ой, приходь же, кума,
Кума-душечка.

Пригощайся, кума,
Необсалюйся
Та в карман та в рукав
Не нахватуйся.

І наїлася я,
І напилася я,
Що насилу до дому
Докотилася я','[''pisni.org.ua'', ''cat:arkhiv-bozhychi'', ''Фольклорний архів анс. "Божичі"'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2159818'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2159818','І учора в куми','І учера в куми,
