INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2159910','Повстанські орли','(Без рідної хати). Українська народна пісня. Виконує: Остап Кіндрачук, Володимир Вермінський','uk','ukr_ssr_1919_1991',NULL,NULL,'Остап Кіндрачук','Цю пісню виконували повстанці УПА з с.Котиківка Городенківського р-ну Івано-Франківської обл. тоді ще малому Остапу Кіндрачуку, який через десятиліття відновив її з пам''яті. В кінці 40-х відділ повстанців рушив у рейд і доля їх невідома, в Котиківці більше повстанці на зв''язок не виходили.','Без рідної буди, не звірі, а люди,
Із лісом збраталися ми.
Топтали закони, фронти і кордони      |
Повстанські завзяті орли.             | (2)

Всю нічку мандруєм і ніг вже не чуєм,
Є в жилах козацькая кров.
Де станеш — ночуєш, де спиш —  там вартуєш,  |
Щоб ворог на карк не зайшов.                 | (2)

Не знаєш де згинеш, де друзів покинеш,
А йдеш і смієшся, і б''єш.
В кривавому танці гуляють повстанці,  |
За ними заграва пожеж.                | (2)

І полем, і лісом з наставленим крісом
Гуляють повстанські орли.
Гуляють орлята та добивають ката —    |
Будують державу свою.                 | (2)','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2159910'), datetime('now')),datetime('now'));
