INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2160859','В Закарпатті радість стала','Українська народна пісня. Виконує: Остап Кіндрачук, Буття','uk','ukr_ssr_1919_1991',NULL,'1939','Співанник УПА','Пісня описує боротьбу Карпатської Січі- війська Карпатської України (проголошено у березні 1939 на Закарпатті з столицею в м.Хуст) проти окупації фашистської Угорщини. Закарпатська Україна перша в Європі вчинила збройний опір нацизму. Польща завдала удару в спину не пропустивши більшу частину галичан-добровольців на оборону Закарпаття, а потім розстрілявши стрільців, які повертались з окупованого Закарпаття в Галичину.','В Закарпатті радість стала, да радість стала, да гей!
Україна там повстала, да там повстала, да гей!
Приспів:
Приказ "Струнко, вправо глянь!"
Там скачуть карі коні, там грають скоростріли,
Б''ють шаблями вправо-вліво, щоб серце не боліло, да гей!
Січ Карпатська маширує, да маширує, да гей!
Аж мадяри ся дивують, да ся дивують, да гей!
Приспів.
А мадяри й нападали, да нападали, да гей!
Закарпаття й плюндрували, да плюндрували, да гей!
Приспів.
Їм поляки помагали, да помагали, да гей!
Удар в спину завдавали, да завдавали, да гей!
Приспів.
А ще німці наступали, да наступали, да гей!
Україну грабували, да грабували, да гей!
Приспів.
А Москва всіх визволяла, да визволяла, да гей!
По Сибірах розселяла, да розселяла, да гей!
Приспів.
По Сибірах розселяла, да розселяла, да гей!
Ще й по тюрмах катувала, да катувала, да гей!
Приспів.
З ворогами битись будем, да битись будем, да гей!
Доки волю не здобудем, да не здобудем, да гей!
Приспів.
В Закарпатті радість стала, да радість стала, да гей!
Україна там повстала, да там повстала, да гей!','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2160859'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2160859','В Закарпатті радість стала','В Закарпатті радість стала, да радість стала, да гей!
