INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_216124','Чи є чи нема Господар Дома','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Чи є чи нема Господар Дома --> РОЗСПІВ: Хутенько Чи- є- чи- не-ма-а- Гос-по-дар- до-ма- Ге-ей- Ко-ля-да-а- Гос-по-дар- До-ма- Колядка стародавня: Українське Різдво Світа. Рай розвився Господь звеселився. В Світлойці суть Золото прядуть. Чи вдома вдома Пані Бабуня Чи є чи нема Господар Дома Буде в Тебе Господь на Вечері. Ой там виxодило та Три Товариші. Радуйся Земле Коляда їде! Наукова цінність Колядок і Щедрівок. При розсліді цих пісень показуєсь, що матеріял, який вони подають, є незвичайно цінним для етнольоґічних дослідів, — і тому рівночасно відчувається потребу більшої кількости записок — і більше вичерпуючих питання, намічені як самим народом, так і дослідником. Α є річчю відомою, що етноґрафічні записки Святочних пісень: Колядок, Щедрівок, Гаїлок і ін., — були роблені досі по-аматорськи, доривочно і безпляново; не пороблено їх у всіх сторонах і місцевостях замешканих Українським народом, так, що вони не вичерпують усіх культурних давніх вартостей, які криються між народом. А нераз одно слово, або одне більше речення має неоціненну вартість для етнольоґічних дослідів. Ще більшу недостачу можна би закинути запискам народних святочних обрядів, тим паче, що ці обряди є погорджувані й нівечені християнською церквою як "поганські", — а інтеліґенцією як наївні повірки й "забобони" — і нарід укриває їх перед небажаними свідками. Колядки й Щедрівки висловом реліґійних ідей. Колядки і Щедрівки не будуть тут віддільно опрацьовані, хоч усе дальше дослідження буде по правді лише їх розслідом. Заложена з початку головна тема праці про Свято Різдва і Щедрого Вечора може бути лише на підставі розсліду Колядок і Щедрівок вичерпана. Навіть можлива дальша тема про Гаїлку знаходить в них своє опертя, бо вони є висловом Староукраїнських традицій реліґійних, суспільних та господарських, на яких основуються Свято Різдва і Щедрого Вечера, а з цими Святами має Гаїлка ідейний зв''язок. Передовсім однак Колядки й Щедрівки є висловом реліґійних ідей, які в довговіковому культурно-історичному розвитку народу назбиралися й уложилися в культурні верстви. Святочні обряди були би для сучасного Українського народу пустою формою, колиб не виповнювали їх ідейним змістом Колядки і Щедрівки. Тому будуть вони розсліджувані в зв''язку з дальшою темою культурно-історичної постаті Староукраїнських свят. Наперед будуть обговорені космоґонійні (світотворчі) Колядки, відтак Колядки іншого культово-реліґійного змісту; опісля буде розглянуто Свято Щедрого Вечера і Водорщів; а за цим будуть опрацьовані Щедрівки. Шанування перших культурних здобутків. Коноплі та льон. На Воведення, по опівночі, жінки сідають голі на порозі хати та прядуть "самосівні" коноплі. Це очевидний натяк на Первісні, ще не добуті людською управою, коноплі. Жінки обсипують сім''ям конопель або льону корови і мастять маслом вимена коровам, щоби добре доїлися. Це пієтизм для конопель і льону, найконечніших у життю ростин: наколиб їх не сотворив Господь враз з іншим насінням у часі творення Землі, мусіли б люди сидіти голі, — як ті жінки на порозі вночі, — жили б у біді та соромі. Насіння льону та конопель благословенне і дуже сівке й родюче, тому то й оця містична поведінка обсипувати цим насінням корови — щоб вони часто були плідні, родили телят і доїлися здорово. Цій містиці відповідає і згадане вже вводження досвіта, того дня, молоднику до хати. Зерно і прядиво. Про Першу пшеницю, Перше жито, про "Овес Самосій" та "Ячмінь Колосій", про Першу сійбу зерна Господом — співають Колядки і величають Бога за ті здобутки культурні; але коноплі, льон, повісма і пряжу цінить нарід може більше, чим збіжжя. Золоту, ідеальну, пшеничку вважає так дорогою, як прядиво: найкрасший добуток з пшениці — це плетений колач, виплетений наче з пряжі з пшеничного тіста. Коляди на спомин перших культурних здобутків. Ось яка ідеольоґічна сполука стає в душі народу на спомин цих неоцінних його Перших культурних здобутків: Колядники під вікном хати співають: Ци є ти дома Ґосподинечка Ци є ти дома Ґосподинечка Ґосподинечка на імя (Анна) Служеньки кажут нема їй дома Нема їй дома гей у Кімнатї Щож она дїє Золото пряде Ходїм до неї колядовати Ой чейже нам дасть по Колядочцї По Колядочцї хоть відзадячко Хоть відзадячко хоть відпрядочки Хоть відпрядочки на шеріночки А Господареві колядують: Ци є ти дома Пан Ґосподарю Ци є ти дома Пан Ґосподарю Пан Ґосподарю на імя (такето) Служеньки кажут нема го дома Нема го дома на Загуменю Ой щож він дїє Золото віє Золото віє Срібло лелїє Ходім до нього колядовати Ой чей же нам дасть добру Коляду Добру Коляду хоть по Коневи Як рівняється вартості золота зерно в господарстві та в життю, так неоцінна, краща золота є пряжа. Як із повісма напряде Господиня на шеріночку для своєї челяди і оця шерінка для них вартує за найдорожшу золоту парчу, так господар вивіє на загуменю зерно золотистої пшениці, з котрої буде передовсім жертва — "Плетений Колач" — на Святовечірній стіл, а з сріблистого жита — хлібець на прожиток. (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) Читати листки з приводу цієї Пісні: Бог, Різдво Світа, Дідух і Лицарі. Українські релігійні роздуми про Бога: Яблучко. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Ідея Бога на Свят-Вечер. Стежки до інших листків про Українські традиції.','Чи є чи нема Господар Дома

Приспів за зразком:
Гей Коляда Господар Дома!

В Стодолойці є Житейко віє
Ходімо ми му заколядуймо
Чи не дасть Він нам по Коробойці

Чи є чи нема Господинейки Дома
У Світлойці є Хлібойко пече
Ходімо ми Їй заколядуймо
Чи не дасть вона нам по Кукілойці

Чи суть чи нема Єго Синойків Дома
В Стаєнойці суть Коники чешуть
Ходімо ми Їм заколядуймо
Чи не дадуть нам по Коникові

Чи суть чи нема Єго Донейків Дома
В Світлойці суть Золото прядуть
Ходімо ми Їм заколядуймо
Чи не дадуть нам по Золотій Нитці','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_216124'), datetime('now')),datetime('now'));
