INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2162012','Бодай тоті Бережани','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. http://zhnyborody.te.ua/ 2. "Пісні Тернопільщини" (Київ, 1989). Записав О. Гижа',NULL,'Бодай тоті Бережани
Вода примулила,
Що не одна мама плаче:
— Нема мого сина!..

Ой не одна мама плаче.
Та не одна тужить:
— Десь мій синок молоденький
Цісареві служить!

Служи, служи, мій синочку,
Будеш мати ласку:
Через плечі білий ремінь,
А на чолі бляшку.

Плачуть мами за синами,
Жінки за мужами,
А молоді дівчатонька
Та й за женихами...

Та що було любе, миле,—
Поплило з водою,
А що було гидке, бридке,—
Говорить зо мною.

(останні два рядки — по двічі)','[''pisni.org.ua'', ''cat:rekrutski'', ''Рекрутські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2162012'), datetime('now')),datetime('now'));
