INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_216199','Нова радість стала **','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Аудіозапис - Ярослав-на. "Колядки"','Підбір акордів: bohdanko','Нова радість стала,
Яка не бувала,
Над вертепом звізда ясна
У весь світ засіяла.

Де Христос родився,
З Діви воплотився,
Як чоловік пеленами
Убого повився.

Пастушки з ягнятком
Перед тим дитятком
На колінця припадають,
Царя-Бога вихваляють.

Ой Ти, Царю, Царю,
Небесний Владарю,
Даруй літа щасливії
Сего дому господарю.

Сего дому господарю
І сій господині,
Даруй літа щасливії
Нашій славній Україні.','[''pisni.org.ua'', ''cat:christian'', ''cat:kolyadky'', ''cat:narodni'', ''cat:shchedrivky'', ''Пісні на християнську тематику'', ''Колядки'', ''Народні пісні'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_216199'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_216199','Нова радість стала **','Нова радість стала,
Яка не бувала,
Над вертепом звізда ясна
У весь світ засіяла.

Де Христос родився,
З Діви воплотився,
Як чоловік пеленами
Убого повився.

Пастушки з ягнятком
Перед тим дитятком
На колінця припадають,
Царя-Бога вихваляють.

Ой Ти, Царю, Царю,
Небесний Владарю,
Даруй літа щасливії
Сего дому господарю.

Сего дому господарю
І сій господині,
Даруй літа щасливії
Нашій славній Україні.');
