INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2161756','Добрий вечір','Музика: Руслана Слова: народні. Виконує: Руслана','uk','ukraine_before_1917',NULL,NULL,'http://www.ruslana.ua',NULL,'Добрий вечір тобі,
Пане господарю, радуйся!
Ой, радуйся земле,
Син Божий народився!

Ой, у Вифлеємі сталася
Новина, радуйся!
Ой, радуйся земле,
Син Божий народився!

Звіщений в пророків у віках
Прадавніх, радуйся!
Ой, радуйся земле,
Син Божий народився!

Він несе спасіння тим серцям,
Що вірять, радуйся!
Ой, радуйся земле,
Син Божий народився!','[''pisni.org.ua'', ''cat:kolyadky'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2161756'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2161756','Добрий вечір','Добрий вечір тобі,
Пане господарю, радуйся!
Ой, радуйся земле,
Син Божий народився!

Ой, у Вифлеємі сталася
Новина, радуйся!
Ой, радуйся земле,
Син Божий народився!

Звіщений в пророків у віках
Прадавніх, радуйся!
Ой, радуйся земле,
Син Божий народився!

Він несе спасіння тим серцям,
Що вірять, радуйся!
Ой, радуйся земле,
Син Божий народився!');
