INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2163596','Відьма','Музика: Віктор Пашник Слова: Віктор Пашник. Виконує: Віктор Пашник','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Em
Зранку до вечора
Am       С
Трудяться рученьки,
Пестять холодну росу.
Em
Очі, що зорі,
Сяють іскрито,
Вітер плете їй косу.
Приспів:
Моя відьмо, моя віро,
Моя леле свята,
В тобі світло,
Em
В тобі миро,
І життя, життя,
Життя! В тобі
Трави-сестриці
Ховають лиці,
Заздрять твоїй красоті
І навіть сонця
Золоті промінці
З неба шепочуть тобі.
Приспів.
Ніжками босими
Землю зігріла
Ходила, квітка росла,
Словами-перлами,
Ліками-веснами
Ніжністю крил летіла.
Приспів.
В ніч на Купала
Зілля збирала,
Вінок пустила у даль,
Цвіт папороті
Людям віддала,
Щастя не було їй, жаль.
Приспів (2)
В тобі!
З ранку до вечора
Трудяться рученьки,
Пестять холодну росу...','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2163596'), datetime('now')),datetime('now'));
