INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2160818','Мамина сорочка','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Мені сорочку мама вишивала
Неначе долю хрестиком вела
Щоб лихих стежинок не шукала
І до людей привітною була
Виконуй доню - мама говорила
Життя закони, істини прості
Не зраджуй землю, що тебе зростила
Не залишай нікого у біді

Приспів (2):
А сорочка мамина біла-біла
А сорочка мамина серцю мила
А сорочка мамина зігріває
Я її до серденька пригортаю

Літа неначе птахи пролітали
Матусі коси дивом зацвіли
І я сорочку білу вишиваю
Як вишивала матінка мені
Виконуй доню - мама говорила
Життя закони, істини прості
Не зраджуй землю, що тебе зростила
Не залишай нікого у біді

Приспів. (2)','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2160818'), datetime('now')),datetime('now'));
