INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2162292','На Івана Купала','Музика: Олег Шак Слова: Петро Мага. Виконує: Ірина Зінковська','uk','ukraine_before_1917',NULL,NULL,'авторське подання',NULL,'Сині очі, сни дівочі,
На Купала дуже темні ночі...
Мала б крила - не стерпіла -
Полетіла б я ще раз охоче туди...
У ніч ворожби...

Туди, де розцвітає рута,
Де п''янка отрута,
Де любов над нами - цар і бог!
Туди, де в нічку темну
Ми любов таємно пили вдвох,
Ми пили разом удвох!

Чарувала, пригортала,
Повертала, але знов втрачала...
Все згоріло, трави вкрили,
Де ходила, з ким, кого кохала тоді
У ніч ворожби...

Тоді, як зацвітає рута,
Де п''янка отрута,
Де любов над нами - цар і бог!
Туди, де в нічку темну
Ми любов таємно пили вдвох,
Ми пили разом удвох!

На Івана, на Купала
Та й на Купала...
На Івана, на Купала
Та й на Купала...
Лети у ніч ворожби!..

Туди, де розцвітає рута,
Де п''янка отрута,
Де любов над нами - цар і бог!
Туди, де в нічку темну
Ми любов таємно пили вдвох,
Ми пили разом удвох!','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2162292'), datetime('now')),datetime('now'));
