INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_216216','Во Вифлеємі нині новина','Музика: о. Нижанковський Слова: о. Нижанковський. Виконує: Гурт КоЛеСо','uk','ukr_ssr_1919_1991',NULL,'1925','Колядки.- Львів: Каменяр, 1990.- 64 с.','Очевидно, автором слів і музики є о. Нижанковський (отець Нижанковський). У книзі "Коляди або пісні з нотами..." (Коляди або пісні з нотами на Різдво Христове.- Жовква: Печатня ОО. Василіян, 1925) під назвою пісні підписано: "о. Нижанковський". У книзі "Колядки" (Колядки.- Львів: Каменяр, 1990.- 64 с.) під назвою пісні підписано: "О. Нижанковський". Але тут не вказано точно, чи є згадана особа автором слів, музики чи їх обробки.','Во Вифлеємі нині новина:
Пречиста Діва зродила Сина,
В яслах сповитий, поміж бидляти,  | (2)
Спочив на сіні Бог необнятий.     |

Вже Херувими славу співають,
Ангельські хори Пана витають,
Пастир убогий несе, що може,  | (2)
Щоб обдарити Дитятко Боже.    |

А ясна зоря світу голосить:
Месія радість, щастя приносить!
До Вифлеєма спішіть всі нині,    | (2)
Бога звитайте в бідній Дитині!   |

За світлом зірки десь аж зі сходу
Йдуть три владики княжого роду,
Золото, дари, кадило, миро            | (2)
Враз з серцем чистим несуть в офіру.  |

Марія Мати Сина леліє,
Йосиф старенький пелени гріє,
А Цар всесвіта в зимні і болю    | (2)
Благословить нас на ліпшу долю.  |

Ісусе милий, ми не багаті,
Золота, дарів не можем дати,
Но дар ціннійший несем від мира,  | (2)
Се віра серця, се любов щира.     |

Глянь оком щирим, о Божий Сину,
На нашу землю, на Україну,
Зішли їй з неба дар превеликий,  | (2)
Щоб Тя славила во вічні віки.    |','[''pisni.org.ua'', ''cat:christian'', ''cat:kolyadky'', ''Пісні на християнську тематику'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_216216'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_216216','Во Вифлеємі нині новина','Во Вифлеємі нині новина:
