INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2162952','Великдень','Музика: Віталій Кирпатовський Слова: Віталій Кирпатовський. Виконує: Людмила Шевченко','uk','ukraine_1991',NULL,NULL,'http://www.stihi.ru/avtor/astroboy','Христос Воскрес!!! Ця пісня до Пасхалії, що триває до Триїці. Пісню можна прослухати і клацнувши мишкою по посиланню далі: http://www.rocklab.ru/view/songs/142043.html','Зранку Сонечко заграло,
Наступає Великдень.
Духу Божому сприяло
Благовіст у церкві - дзень.

Вгору Святий Дух піднесе.
Там музики з під небес.
Скажемо: "Христос Воскресе!".
Він Воістину Воскрес!

Променистий день щасливий.
Світять небо і життя.
З нами знов Христосе милий,
Мирне, чисте каяття.

Мить велика, час ласкавий!
Дзвони - птахи голубі.
Боже святий, Боже правий,
Славу творимо тобі!','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:voskresni'', ''Церковні пісні'', ''Воскресні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2162952'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2162952','Великдень','Зранку Сонечко заграло,
Наступає Великдень.
Духу Божому сприяло
Благовіст у церкві - дзень.

Вгору Святий Дух піднесе.
Там музики з під небес.
Скажемо: "Христос Воскресе!".
Він Воістину Воскрес!

Променистий день щасливий.
Світять небо і життя.
З нами знов Христосе милий,
Мирне, чисте каяття.

Мить велика, час ласкавий!
Дзвони - птахи голубі.
Боже святий, Боже правий,
Славу творимо тобі!');
