INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2163717','Злагода','Музика: Геннадій Татарченко Слова: Вадим Крищенко. Виконує: Іво Бобул, Лілія Сандулеса, Таїсія Повалій, Олександр Пономарьов','uk','ukraine_1991',NULL,NULL,'Книга: Крищенко В. Д. Усі ми прагнемо любові: Пісні.-Київ:ВіРА ІНСАЙТ- 2003',NULL,'Щасливі ті батьки і діти,
Яких мине гірка пора.
Ой, треба вміти, треба вміти
Ростити паростки добра.
Добро не родиться од злості-
І в цьому істина проста.
Нехай частіш до нас у гості
Приходить злагода свята.

Приспів:
Несімо злагоду, як ту дитину-
У кожну хату і у родину.
Нам треба злагоди, а зла не треба-
Хай посміхнеться всім земля і небо.
Несімо злагоду, як Божу милість,-
І завжди будемо в добрі та силі.
Нам треба злагоди, а зла не треба,
Хай посміхнеться всім земля і небо.

Ми натерпілися багато
Від різних непорозумінь.
Нехай братерства світле свято
Не закриває чорна тінь.
Болюча темна ворожнечо,
У нашу душу не приходь.
"Кладімо злагоду на плечі",-
Заповідає нам Господь.

Приспів','[''pisni.org.ua'', ''cat:zahalni-cinnosti'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2163717'), datetime('now')),datetime('now'));
