INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2164313','Криниця','Музика: Олександр Зуєв Слова: Вадим Крищенко. Виконує: Василь Бокоч','uk','ukraine_1991',NULL,NULL,'Книга: Крищенко В. Д. Усі ми прагнемо любові: Пісні.-Київ:ВіРА ІНСАЙТ- 2003',NULL,'Не всихає у степу криниця.
А вода в криниці дзвонкова.
Поспішає врода яснолиця
На запросин лагідні слова.

Приспів:
Дай мені напиться,
Степова кринице,
Де пшениця гони простягла.
Дай, як мати сину,
Ту одвічну силу
З рідного земного джерела.

Заяснились ніжні переливи,
Із любові пісня вироста.
Над водою, над студеним дивом
Нахиляю радісні вуста.

Приспів.

Зустрічає літо жнивну днину
З ласкою в натрудженій руці.
На добро, на долю соколину
Б''ють снагою чисті криниці.

Приспів.','[''pisni.org.ua'', ''cat:zahalni-cinnosti'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2164313'), datetime('now')),datetime('now'));
