INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2162890','Пізня зустріч','Музика: Мар''ян Гаденко Слова: Вадим Крищенко. Виконує: Іво Бобул, Лілія Сандулеса, Мар''ян Гаденко, Інеш','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Зустріч наша пізня, як прив''яла пісня:
Пригадався наспів - та забув слова.
Лиш обпалить серцем, болем доторкнеться,
Вже життя чекаю, а тебе нема...

Приспів:
Скажи мені, чом стрілися так пізно,
Коли вже літо в осінь відійшло?
В моїм житті навиділося різне,
Але того, що треба не було.
Чому дороги наші не зійшлися
Тоді, як літо сіяло тепло?
Тепер губами хочем притулиться -
Та поміж нас холодне мокре скло.

Ой, стрічання пізне - нескоромне, пісне,
Бо в очах не осінь, а уже - зима.
На стареньких струнах чується відлуння,
Доліта відлуння, голосу ж нема...

Приспів. (2)','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2162890'), datetime('now')),datetime('now'));
