INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2164563','Мамо моя','Музика: Атаназій Чейпеш Слова: Атаназій Чейпеш. Виконує: Гурт Єдині','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Залишаю усе,
Поспішаю до тебе на свято,
Може, зустрічей тих
Залишилось не так вже й багато,
І коли я прийду,
І постукаю тихо до хати,
А мені відчинить двері моя мати!

Приспів:
Мамо моя, мамо моя,
Голубко сива,
Скільки біди, скільки тривог
Ти пережила.
Мамо моя, мамо моя,
Добра ти ненько,
Дай я тобі поклонюся
Сьогодні низенько.

Покидаю усе,
Поспішаю до тебе на свято,
Рідна ненько моя,
Бачу, як ти стоїш біля хати
І підемо туди,
Де колись ми ходили з тобою,
Де дитинство моє проплива,
Як хвиля рікою.

Приспів.

Речитатив:
Мамо моя, вже минули роки,
Як я не бачив твоїх добрих очей,
В мому серці лежить журба,
Коли згадуються мені твої добрі руки,
Але тебе немає поряд,
Тебе нема біля мене,
Прости мене,
Прости мене, мамо, за все,
Молю, прости...

Залишаю усе,
Поспішаю до тебе на свято,
Може, зустрічей тих
Залишилось не так вже й багато,
І коли я прийду,
І постукаю тихо до хати,
А мені не відчинить двері моя мати...

Приспів. (2)','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2164563'), datetime('now')),datetime('now'));
