INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2165055','Бажаю щастя','Музика: Лариса Недін Слова: Вадим Крищенко. Виконує: Лариса Недін','uk','ukraine_1991',NULL,NULL,'Книга: Крищенко В. Д. Усі ми прагнемо любові: Пісні.-Київ:ВіРА ІНСАЙТ-2003',NULL,'Хай не йде до серця туга,
Хоч і час до неї звик.
Порадійте ви за друга,
Збудьтесь заздрощів навік.
І хай родить наше поле,
І хай світиться душа,
І людська біда ніколи
Хай не буде нам чужа.

Приспів:
Бажаю щастя -
Скажімо один одному.
Бажаю щастя -
Скажемо усім.
І, неприємності забувші і утому,
Сердечним словом світ благословім.

Ні, не бійтеся зігріти
Чи підтримати когось.
Заплетіть пахучі квіти
У вінок тугих колось.
Не шкодуйте, не жалійте
Слів, де щирість і тепло.
І добро повсюди сійте,
Щоб у душах проросло.

Приспів.

Не шкодуйте, не жалійте
Слів, де щирість і тепло.
І добро повсюди сійте,
Щоб у душах проросло.
Треба вірити у себе,
Щоб з''єднались дух і плоть,
Треба вірити, що з неба
Допоможе нам Господь.

Приспів.','[''pisni.org.ua'', ''cat:zahalni-cinnosti'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2165055'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2165055','Бажаю щастя','Хай не йде до серця туга,
