INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2163726','Братове','Музика: Павло Мрежук Слова: Вадим Крищенко. Виконує: Павло Мрежук','uk','ukraine_1991',NULL,NULL,'Книга: Крищенко В. Д. Усі ми прагнемо любові: Пісні.-Київ:ВіРА ІНСАЙТ- 2003',NULL,'Як засушить душу
Сум, як суховій,
Поділитись мушу-
Є товариш мій.
Як іду угору
В пелену зав''юг,
Краще, якщо поруч
Біля мене друг.

Приспів:
Добре, братове, що ви є на світі,-
Спертись мені є кому на плече.
Добре, братове, що сонцем зігріту,
Стріну довірливість ваших очей.
Добре, братове, що ми разом з вами
Можемо стать проти кривди й біди.
Добре, що доля зове нас братами,-
Так би усюди і так би завжди.

Не носімо злості,
Не зовім хули-
Краще йдімо в гості,
Сядьмо за столи.
І всі негаразди,
Підігріті злом,
Переборем разом,
Якщо ми разом.

Приспів.','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2163726'), datetime('now')),datetime('now'));
