INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2164410','Єдність','Музика: Леонід Нечипорук Слова: Вадим Крищенко. Виконує: Павло Мрежук','uk','ukraine_1991',NULL,NULL,'Книга: Крищенко В. Д. Усі ми прагнемо любові: Пісні.-Київ:ВіРА ІНСАЙТ-2003',NULL,'Нам треба в люди єдність нести,
Обходячи негоди злі,
Бо ми усі брати і сестри
На рідній батьківський землі.
Хай день цвіте весняним рястом,
Добро сердець не знає меж,
Бо неподільне наше щастя
І лихо неподільно теж.

Приспів:
Де єдність - там воля,
Де єдність - там сила,
Там кривди лихої нема.
Хай мати-Вкраїна
Щаслива й красива
У єдності всіх обніма.

В родині грішно розділяти
І повторять: твоє, моє...
Хай щирість скрізь іде до хати
І правда у цимбали б''є.
Доволі сварок і гордині -
Нам інших вистачить турбот.
Коли ми дружні та єдині -
То ми незборений народ.

Приспів.','[''pisni.org.ua'', ''cat:zahalni-cinnosti'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2164410'), datetime('now')),datetime('now'));
