INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2166216','Останній дзвоник','Музика: Михайло Чемберджі Слова: Вадим Крищенко','uk','ukraine_1991',NULL,NULL,'Книга: Крищенко В. Д. Усі ми прагнемо любові: Пісні.-Київ:ВіРА ІНСАЙТ-2003','З репертуару багатьох дитячих колективів','В синій вечір заплітає школа
Дзвоника останні позивні.
А на серці терпко, як ніколи,
І тобі сьогодні, і мені.

Приспів:
А день новий уже зорить світанням,
У путь-дорогу кличе нас.
І обіймає музика прощання
Наш випускний десятий клас.

Ні, нема щасливіших на світі,
Ніж оті, кому сімнадцять літ.
І слова, любов''ю обігріті,
Нам учитель промовляє вслід.

Приспів.

За вікном дитинства світ широкий
В очі сипле зорі золоті.
Рідна школо, ми твої уроки
Ще не раз згадаємо в житті.

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2166216'), datetime('now')),datetime('now'));
