INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2166596','Весілля','Музика: Олександр Морозов Слова: Вадим Крищенко. Виконує: Іво Бобул','uk','ukraine_before_1917',NULL,NULL,'Книга: Крищенко В. Д. Усі ми прагнемо любові: Пісні.-Київ:ВіРА ІНСАЙТ-2003',NULL,'Ой весілля, як насіння -
Сіє дзвони навкруги,
На покоси жовтокосі,
На поля і на луги.

Приспів:
Ой весілля, як чар-зілля -
Тільки пий його до дна,
Щоб для двох сердець привітних
Доля склалася одна.

Хата вікнами ясніє
І у далеч загляда:
Чи не їдуть, чи не їдуть
Молодий і молода?

Приспів.

Грає скрипка в повний голос
І завзято бубон б''є,
Що було - перемололось,
А лишилось те, що є.

Приспів.

Їдуть, їдуть молодята -
Голос дальній доліта,
Хліб і сіль виносять з хати -
На добро і на літа.

Приспів.

Скрипка грає, не вгаває,
Співом в душу заповза.
Посміхнулася матуся,
А під віями - сльоза.

Приспів.','[''pisni.org.ua'', ''cat:vesilni'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2166596'), datetime('now')),datetime('now'));
