INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2165073','Благословенний Києве...','Музика: Володимир Домшинський Слова: Вадим Крищенко. Виконує: Павло Мрежук','uk','ukraine_1991',NULL,NULL,'Книга: Крищенко В. Д. Усі ми прагнемо любові: Пісні.-Київ:ВіРА ІНСАЙТ-2003',NULL,'Я під київське небо, як на сповідь, іду,
Щоб утіху відчуть і притишить біду,
Щоб поглянуть навкруг і побачить Дніпро,
Щоб єднались в душі і любов, і добро.
Я всім серцем відчув - і сказать не боюсь:
Українська колиска - наша Київська Русь.
Ми зросли і ростем, підійнявшись з колін,
Під святої Софії розлунистий дзвін.

Приспів:
Я на київські схили
Знов прийду, ти прийдеш.
Володимирська гірка -
Стеля київських веж.
Тут Святий Володимир
Зняв свій хрест в синю вись.
Звідси з Божої волі,
Певно, й ми почались.

Володимирська гірка - з неї видно усе:
Київ голову гордо, не схиливши, несе.
І золочені храми, наче свічі, горять,
Щоб на Київ Господь посилав благодать.

Приспів:
Я на київські схили
Знов прийду, ти прийдеш.
Володимирська гірка -
Стеля київських веж.
Промовля Володимир
Із хрестом угорі:
Будь же, Києве наш,
В щасті, в мирі й добрі.','[''pisni.org.ua'', ''cat:kyyiv'', ''Пісні про Київ'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2165073'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2165073','Благословенний Києве...','Я під київське небо, як на сповідь, іду,
Щоб утіху відчуть і притишить біду,
Щоб поглянуть навкруг і побачить Дніпро,
Щоб єднались в душі і любов, і добро.
Я всім серцем відчув - і сказать не боюсь:
Українська колиска - наша Київська Русь.
Ми зросли і ростем, підійнявшись з колін,
Під святої Софії розлунистий дзвін.

Приспів:
Я на київські схили
Знов прийду, ти прийдеш.
Володимирська гірка -
Стеля київських веж.
Тут Святий Володимир
Зняв свій хрест в синю вись.
Звідси з Божої волі,
Певно, й ми почались.

Володимирська гірка - з неї видно усе:
Київ голову гордо, не схиливши, несе.
І золочені храми, наче свічі, горять,
Щоб на Київ Господь посилав благодать.

Приспів:
Я на київські схили
Знов прийду, ти прийдеш.
Володимирська гірка -
Стеля київських веж.
Промовля Володимир
Із хрестом угорі:
Будь же, Києве наш,
В щасті, в мирі й добрі.');
